(83, 32, '_wp_page_template', 'default'),
(84, 32, 'dirigido_a', 'Personal de salud involucrado en actividades docentes en el IMSS'),
(85, 32, 'acerca', 'La Coordinación de Educación en Salud del Instituto Mexicano del Seguro Social se congratula al presentar este curso cuyo propósito es dotar al personal de salud de herramientas científicamente fundamentadas para el desarrollo de la labor docente que desempeña con el fin de lograr disponer de los mejores profesionales de salud en beneficio de los derechohabientes.'),
(86, 32, 'objetivo', 'Dirigir el aprendizaje del personal de salud a su cargo mediante el empleo de estrategias educativas para lograr un aprendizaje significativo.'),
(87, 32, 'contenido', '1. Modalidad semipresencial\r\n2. Proceso de enseñanza y aprendizaje en la modalidad semipresencial\r\n3. Estrategias educativas de la modalidad semipresencial\r\n4. Clase inversa\r\n5. Educación basada en casos'),
(88, 32, 'image', 'Estrategias-educativas-docente.jpg'),
(89, 33, '_wp_page_template', 'default'),
(90, 33, 'dirigido_a', 'Personal médico de primer nivel de atención del IMSS'),
(91, 33, 'acerca', 'El propósito de este curso es capacitar al personal médico con conocimientos actualizados sobre las enfermedades exantemáticas de mayor relevancia epidemiológica, a fin de lograr su prevención, diagnóstico y tratamiento oportunos.'),
(92, 33, 'objetivo', 'Establecer el diagnóstico de las enfermedades exantemáticas más frecuentes en primer nivel de atención, a fin de implementar el tratamiento adecuado.'),
(93, 33, 'contenido', '1. Sarampión\r\n2. Rubéola\r\n3. Escarlatina\r\n4. Varicela\r\n5. Exantema súbito\r\n6. Eritema infeccioso\r\n7. Exantema vesículo-ampolloso\r\n8. Otras enfermedades exantemáticas'),
(94, 33, 'image', ''),
(95, 34, '_wp_attached_file', '2026/04/exantematicas-scaled-1.jpg'),
