(289, 67, 'acerca', 'El propósito de este curso es capacitar al equipo multidisciplinario de salud sobre el Protocolo de Atención Integral (PAI) Código cerebro, desarrollado por el Instituto para estandarizar acciones de prevención, diagnóstico y tratamiento de pacientes adultos con un evento vascular cerebral.'),
(290, 67, 'objetivo', 'Identificar al Protocolo de Atención Integral Código cerebro como un nuevo modelo de atención que permite homologar las acciones de prevención, diagnóstico y tratamiento de pacientes con un evento vascular cerebral en los tres niveles de atención, a fin de utilizarlo en la práctica profesional.'),
(291, 67, 'contenido', '<strong>Sección 1. Video introductorio PAI Código cerebro </strong>\r\n\r\n<strong>Sección 2. Unidad PAI Código cerebro </strong>\r\n<ul>\r\n 	<li>Tema 1. Prevención primaria: promoción a la salud</li>\r\n 	<li>Tema 2. Admisión Continua</li>\r\n 	<li>Tema 3. Unidad de Cuidados Intensivos, rehabilitación física y terapia del lenguaje\r\n<ul>\r\n 	<li>Ejercicio: actividades del personal médico y de enfermería</li>\r\n 	<li>Ejercicio: adivina quién</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<strong>Sección 3. Materiales complementarios </strong>\r\n<ul>\r\n 	<li>Infografía: PAI Código cerebro: triage</li>\r\n 	<li>Infografía: PAI Código cerebro: evaluación médica</li>\r\n 	<li>Infografía: PAI Código cerebro: evaluación por imagen</li>\r\n 	<li>Infografía: PAI Código cerebro: mantenimiento de la perfusión cerebral</li>\r\n</ul>'),
(292, 67, 'image', 'PAI-Codigo-Cerebro-equipo-salud.jpg'),
(293, 68, '_wp_page_template', 'default');
INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(294, 68, 'dirigido_a', 'Personal médico y directivo de los tres niveles de atención del IMSS'),
(295, 68, 'acerca', 'En el IMSS, la lumbalgia causa aproximadamente 907 552 consultas al año en el primer nivel de atención, lo que representa una tasa estimada de 157 casos por cada 10 mil derechohabientes. Hasta el 90% de los casos presenta remisión en las primeras seis semanas; sin embargo, del 2 al 7% de los afectados pueden desarrollar dolor crónico, que a su vez causa hasta el 85% del ausentismo laboral por parte del trabajador.\r\nAnte esta problemática, el IMSS ha desarrollado un Protocolo de Atención Integral  (PAI) en el que se establecen pautas de actuación del personal de salud de los tres niveles de atención, a fin de homologar las actividades referentes a la atención integral de pacientes con lumbalgia.\r\nPor ello, la Dirección de Prestaciones Médicas del Instituto Mexicano del Seguro Social considera fundamental la capacitación del personal en materia de investigación cualitativa en salud.'),
(296, 68, 'objetivo', 'Utilizar el Protocolo de Atención Integral  (PAI) Lumbalgia inespecífica en su práctica profesional, a fin de homologar las actividades del equipo multidisciplinario de salud en los diferentes niveles de atención.'),
(297, 68, 'contenido', '<ol>\r\n 	<li>Introducción</li>\r\n 	<li>Unidad Protocolo de Atención Integral Lumbalgia inespecífica</li>\r\n 	<li>Materiales complementarios</li>\r\n</ol>'),
(298, 68, 'image', 'PAI-Lumbalgia-Medicos2.jpg'),
(299, 69, '_wp_page_template', 'default'),
