(341, 77, '_wp_page_template', 'default'),
(342, 77, 'dirigido_a', 'Médicos directivos de los tres niveles de atención del IMSS.'),
(343, 77, 'acerca', 'El propósito de este curso es dotar a dicho personal de herramientas que le ayuden a realizar una adecuada supervisión y control de la prescripción de ITT, a fin de hacer más eficientes las gestiones médico-administrativas relacionadas con este proceso.'),
(344, 77, 'objetivo', 'Distinguir los recursos necesarios para la supervisión y el control del proceso de prescripción de ITT, a fin de utilizarlos en su práctica diaria.'),
(345, 77, 'contenido', '<ol>\n 	<li>Bases conceptuales y legales para la expedición de la incapacidad temporal para el trabajo</li>\n 	<li>Comité para el control de la incapacidad temporal para el trabajo (COCOITT)</li>\n 	<li>Elementos para el adecuado llenado del certificado de ITT</li>\n 	<li>Herramientas electrónicas para el control de la ITT</li>\n 	<li>La comunicación en el proceso de prescripción de incapacidades temporales para el trabajo</li>\n</ol>'),
(346, 77, 'image', ''),
(347, 78, '_wp_attached_file', '2026/04/Prescripcion-razonada-incapacidad-medico-directivo-scaled-1.jpg'),
