(364, 80, '_thumbnail_id', '81'),
(365, 82, '_wp_page_template', 'default'),
(366, 82, 'dirigido_a', 'Personal médico con funciones directivas y operativas de las Unidades Médicas de primer, segundo y tercer nivel de atención, personal de la Unidad Médica con funciones operativas o administrativas de las Unidades de primer, segundo y tercer nivel.'),
(367, 82, 'acerca', 'La salud como fenómeno complejo debe estudiarse desde diferentes aproximaciones y metodologías que permitan la producción de conocimiento útil para mejorar la calidad de la atención y promoción de la salud que proporciona el Instituto Mexicano del Seguro Social.\r\nPor ello, la Dirección de Prestaciones Médicas del Instituto Mexicano del Seguro Social considera fundamental la capacitación del personal en materia de investigación cualitativa en salud.'),
(368, 82, 'objetivo', 'Comprender los fundamentos teóricos y metodológicos de la investigación cualitativa, a fin de utilizarlos para sustentar un proyecto de investigación en salud.'),
(369, 82, 'contenido', '<ol>\r\n 	<li>Generalidades de la investigación cualitativa</li>\r\n 	<li>El surgimiento de la investigación cualitativa en México y Latinoamérica</li>\r\n 	<li>Metodología de la investigación cualitativa I</li>\r\n 	<li>Metodología de la investigación cualitativa II</li>\r\n 	<li>Implementación de la investigación cualitativa en salud I</li>\r\n 	<li>Implementación de la investigación cualitativa en salud II</li>\r\n</ol>'),
(370, 82, 'image', 'Introduccion-investigacion-cualitativa-salud.jpg'),
(371, 83, '_wp_page_template', 'default'),
(372, 83, 'dirigido_a', 'Personal médico de primer nivel de atención del IMSS'),
(373, 83, 'acerca', 'El presente curso busca capacitar al personal médico con conocimientos actualizados para la atención de los trastornos adictivos más frecuentes. El personal médico desarrollará competencias para implementar acciones de prevención, consejería, diagnóstico y tratamiento de dichas enfermedades a fin de reducir el riesgo de complicaciones en pacientes que acuden a los servicios institucionales de primer nivel de atención.'),
(374, 83, 'objetivo', 'Establecer el diagnóstico de los trastornos adictivos más frecuentes en atención primaria para implementar el tratamiento adecuado que permita disminuir el riesgo de complicaciones.'),
(375, 83, 'contenido', '<ol>\r\n 	<li>Generalidades de las adicciones</li>\r\n 	<li>Trastornos relacionados con tabaco y alcohol</li>\r\n 	<li>Trastornos relacionados con alucinógenos</li>\r\n 	<li>Trastornos relacionados con estimulantes</li>\r\n 	<li>Trastornos relacionados con sustancias depresoras</li>\r\n 	<li>Trastorno por juego</li>\r\n 	<li>Otros trastornos adictivos no relacionados con sustancias</li>\r\n 	<li>Trastornos relacionados con fármacos psicotrópicos</li>\r\n 	<li>Trastornos relacionados con inhalantes</li>\r\n 	<li>Prevención, detección temprana y consejería de adicciones</li>\r\n</ol>'),
(376, 83, 'image', 'Transtornos-Adictivos-Frecuentes.jpg'),
(377, 84, '_wp_page_template', 'default'),
(378, 84, 'dirigido_a', 'Enfermeras y enfermeros auxiliares, generales, especialistas y jefes de piso de los tres niveles de atención del IMSS'),
(379, 84, 'acerca', 'El papel que desempeña el personal de Enfermería es imprescindible para todos los procesos de atención a la salud, por ello, el 2020 ha sido declarado por la OMS como el año de la Enfermería y la partería. De manera imprevista, este año, los profesionales de esta discliplina enfrentaron un reto trascendental ante el cual reafirmaron la valía de su quehacer: la pandemia de COVID-19.'),
(380, 84, 'objetivo', 'Identificar los aspectos esenciales para la atención de Enfermería a pacientes con enfermedad por coronavirus 2019 (COVID-19), a fin de reconocer su importancia y utilizarlos en su práctica profesional.'),
(381, 84, 'contenido', '<ol>\r\n 	<li>Aspectos biopsicosociales durante la atención de Enfermería a pacientes con COVID-19</li>\r\n 	<li>Enfermería en la prevención de la COVID-19</li>\r\n 	<li>Enfermería en el tratamiento de la COVID-19</li>\r\n</ol>'),
(382, 84, 'image', ''),
(383, 85, '_wp_attached_file', '2026/04/COVID19-Temas-selectos-Enfermeria.jpg'),
