(386, 86, '_wp_page_template', 'default'),
(387, 86, 'dirigido_a', 'Personal médico adscrito al primer nivel de atención del IMSS'),
(388, 86, 'acerca', 'Por medio de este curso, el personal médico desarrollará competencias que le permitirán proporcionar atención a la mujer con expectativas de embarazo, realizar el control prenatal con base en la normatividad vigente, establecer de manera oportuna el diagnóstico de las principales entidades nosológicas que complican el embarazo e implementar un tratamiento a fin de disminuir la morbimortalidad materna y perinatal.'),
(389, 86, 'objetivo', 'Al finalizar el curso usted será capaz de establecer un plan de tratamiento integral para mujeres con expectativas de embarazo, con un embarazo normoevolutivo o que presentan complicaciones, a fin de disminuir la morbimortalidad materna y perinatal.'),
(390, 86, 'contenido', '<ol>\r\n 	<li>Atención preconcepcional y control prenatal</li>\r\n 	<li>Enfermedades que complican el embarazo</li>\r\n 	<li>Complicaciones frecuentes del embarazo</li>\r\n 	<li>Atención de las emergencias obstétricas</li>\r\n 	<li>Emergencias en el embarazo, parto y puerperio</li>\r\n 	<li>Atención del puerperio y del recién nacido</li>\r\n</ol>'),
(391, 86, 'image', ''),
