(395, 88, '_wp_page_template', 'default'),
(396, 88, 'dirigido_a', 'Personal médico de los tres niveles de atención y médicos residentes del IMSS'),
(397, 88, 'acerca', 'Hoy en día, el SARS-CoV-2 se ha extendido a cientos de países y ha ocasionado miles de casos de COVID-19, por lo que la Organización Mundial de la Salud (OMS) la ha catalogado como una pandemia. \r\nEs por ello,  que el Instituto Mexicano del Seguro Social, a través de la Dirección de Prestaciones Médicas, pone a disposición del personal de salud el curso COVID-19: Temas selectos para el personal médico.'),
(398, 88, 'objetivo', 'Identificar aspectos relevantes de la prevención, diagnóstico y tratamiento de la enfermedad por coronavirus 2019, a fin de utilizar estos conocimientos en su práctica médica para contribuir al control de este padecimiento.'),
(399, 88, 'contenido', '<ol>\r\n 	<li>Temas selectos de prevención de COVID-19</li>\r\n 	<li>Temas selectos de diagnóstico de COVID-19</li>\r\n 	<li>Temas selectos de tratamiento de COVID-19</li>\r\n</ol>'),
(400, 88, 'image', ''),
