(404, 90, '_wp_page_template', 'default'),
(405, 90, 'dirigido_a', 'Personal de laboratorio de los tres niveles de atención del IMSS'),
(406, 90, 'acerca', 'Debido a que el número de personas infectadas con COVID-19 se incrementa a nivel mundial y éstas deben ser atendidas por los sistemas de salud, el laboratorio clínico desempeña un papel fundamental en la detección, diagnóstico, tratamiento y seguimiento de los pacientes infectados con esta enfermedad. Por ello, es imprescindible que el personal de laboratorio cuente con las herramientas necesarias para mantener un ambiente de trabajo seguro a fin de prevenir la exposición laboral al SARS-CoV-2.'),
(407, 90, 'objetivo', 'Identificar las medidas de prevención en el laboratorio y las directrices para las pruebas diagnósticas en el contexto de la COVID-19, a fin de utilizarlas para fortalecer su práctica profesional.'),
(408, 90, 'contenido', '<ol>\r\n 	<li>Prevención de la COVID-19 para el personal de laboratorio</li>\r\n 	<li>Directrices de laboratorio para el diagnóstico de la COVID-19</li>\r\n</ol>'),
(409, 90, 'image', ''),
(410, 91, '_wp_attached_file', '2026/04/COVID19-Temas-selectos-laboratorio.jpg'),
