(412, 90, '_thumbnail_id', '91'),
(413, 92, '_wp_page_template', 'default'),
(414, 92, 'dirigido_a', 'Personal de Enfermería y Trabajo Social; psicólogos clínicos, médicos familiares, médicos psiquiatras, médicos SPPSTIMSS, médicos no familiares de salud en trabajo, coordinadores clínicos de salud en el trabajo, jefes de coordinación y evaluación de salud en el trabajo, coordinadores auxiliares médicos de salud en el trabajo, coordinadores delegacionales de salud en el trabajo, médicos generales, médicos no familiares que atienden pacientes en áreas COVID y médicos residentes del IMSS.'),
(415, 92, 'acerca', 'Capacitar al personal de salud con conocimientos sobre instrumentos y herramientas para proporcionar atención oportuna e integral a los derechohabientes y a compañeros que están al frente de la atención durante la actual contingencia por COVID-19, que se presenten con afectaciones en la salud mental en las Unidades de Medicina Familiar y SPPSTIMSS.'),
(416, 92, 'objetivo', 'Utilizar los principales elementos relacionados con la salud mental durante la contingencia por COVID-19, a fin de proporcionar atención integral a pacientes, familiares y personal de salud del Instituto Mexicano del Seguro Social.'),
(417, 92, 'contenido', '<ol>\r\n 	<li>Afectaciones en la salud mental durante la contingencia por COVID-19</li>\r\n 	<li>Herramientas de apoyo emocional durante la contingencia por COVID-19</li>\r\n 	<li>Apoyo emocional durante la contingencia por COVID-19</li>\r\n 	<li>Enfermedades mentales y del comportamiento debidas al trabajo</li>\r\n</ol>'),
