(421, 92, '_thumbnail_id', '93'),
(422, 94, '_wp_page_template', 'default'),
(423, 94, 'dirigido_a', 'Médicos no familiares, médicos familiares, especialistas en medicina física y rehabilitación, terapistas físicos, terapistas ocupacionales, fonoaudiólogos, Enfermería, Trabajo Social, Nutrición, Psicología y Audiología/Foniatría'),
(424, 94, 'acerca', 'El propósito de este curso es capacitar al personal médico y paramédico sobre el lineamiento para la rehabilitación integral pos-COVID-19, que fue desarrollado por el Instituto para estandarizar acciones de prevención, diagnóstico y tratamiento de las posibles secuelas en pacientes afectados por esta enfermedad.'),
(425, 94, 'objetivo', 'Identificar las bases para la atención médica y paramédica en rehabilitación integral pos-COVID-19, a fin de utilizarlas para reconocer las secuelas que presenta el paciente, reducir la discapacidad y restablecer su condición física, cognitiva, psicológica, social y laboral.'),
(426, 94, 'contenido', '<ol>\r\n 	<li>Fundamentos de la rehabilitación integral pos-COVID-19</li>\r\n 	<li>Rehabilitación integral pos-COVID-19 en el IMSS</li>\r\n</ol>'),
(427, 94, 'image', ''),
(428, 95, '_wp_attached_file', '2026/04/Introduccion-rehabilitacion-integral-post-COVID19-scaled-1.jpg'),
