(478, 104, '_thumbnail_id', '105'),
(479, 106, '_wp_page_template', 'default'),
(480, 106, 'dirigido_a', 'Personal de salud (Medicina, Enfermería, Trabajo Social y Nutrición)'),
(481, 106, 'acerca', 'Como lo establecen la Secretaría de Salud y la Comisión Nacional de Bioética, promover el conocimiento y la aplicación de la bioética en los ámbitos científico, tecnológico y de la salud con una perspectiva laica, social y global es imprescindible para lograr condiciones de justicia, equidad y respeto a los derechos humanos en todas las dimensiones de la salud.'),
(482, 106, 'objetivo', 'Utilizar los conocimientos sobre bioética a fin de analizar situaciones de preocupación en esta materia que se presentan en la práctica cotidiana y realizar acciones que contribuyan a mejorar la calidad de la atención.'),
(483, 106, 'contenido', '1. Fundamentos de bioética y ética médica\r\n2. El principio de autonomía en la atención a la salud\r\n3. Responsabilidad y calidad en el proceso de atención\r\n4. Temas de bioética al inicio de la vida y en la atención obstétrica\r\n5. Temas de bioética en el paciente pediátrico\r\n6. Temas de bioética al final de la vida\r\n7. Bioética en la administración hospitalaria\r\n8. Ética en la investigación clínica\r\n9. Casos prácticos'),
(484, 106, 'image', 'Introduccion-bioetica-ambito-clinico.jpg'),
(485, 107, '_wp_attached_file', '2026/04/Introduccion-bioetica-ambito-clinico.jpg'),
