(529, 116, '_wp_page_template', 'default'),
(530, 116, 'dirigido_a', 'Personal médico del primer nivel de atención del IMSS'),
(531, 116, 'acerca', 'En el mundo, alrededor de cada cuatro segundos ocurre un infarto agudo de miocardio y, cada cinco segundos, un evento vascular cerebral. La principal razón de la aparición de estas enfermedades se asocia con malos hábitos higiénico-dietéticos, causantes de sobrepeso y obesidad, el sedentarismo, el tabaquismo, entre otros. \r\nEs por ello que resulta necesario que el personal médico cuente con conocimientos actualizados sobre el diagnóstico, tratamiento y prevención de las enfermedades cardiovasculares más frecuentes en el primer nivel de atención, con la finalidad de implementar medidas preventivas eficaces para contribuir en la atención de este problema.'),
(532, 116, 'objetivo', 'Establecer el diagnóstico oportuno y el tratamiento adecuado de las enfermedades cardiacas que se presentan con mayor frecuencia en el primer nivel de atención, a fin de reducir la morbimortalidad por estos padecimientos en la población.'),
(533, 116, 'contenido', '<strong>Unidad 1. Aspectos generales de cardiología</strong>\r\n<ul>\r\n 	<li>Tema 1. Fundamentos de cardiología</li>\r\n 	<li>Tema 2. Evaluación del paciente con cardiopatía</li>\r\n 	<li>Tema 3. Fármacos de uso frecuente en cardiología</li>\r\n</ul>\r\n<strong>Unidad 2. Hipertensión arterial</strong>\r\n<ul>\r\n 	<li>Tema 1. Aspectos generales de la hipertensión arterial</li>\r\n 	<li>Tema 2. Diagnóstico de la hipertensión arterial</li>\r\n 	<li>Tema 3. Tratamiento de la hipertensión arterial</li>\r\n 	<li>Tema 4. Complicaciones de la hipertensión arteria</li>\r\n</ul>\r\n<strong>Unidad 3. Cardiopatía isquémica</strong>\r\n<ul>\r\n 	<li>Tema 1. Aspectos generales de la cardiopatía isquémica</li>\r\n 	<li>Tema 2. Angina estable Tema 3. Síndrome isquémico coronario agudo</li>\r\n</ul>\r\n<strong>Unidad 4. Arritmias cardiacas</strong>\r\n<ul>\r\n 	<li>Tema 1. Aspectos generales de las arritmias cardiacas</li>\r\n 	<li>Tema 2. Bradiarritmias más frecuentes en el primer nivel de atención</li>\r\n 	<li>Tema 3. Taquiarritmias más frecuentes en el primer nivel de atención</li>\r\n</ul>\r\n<strong>Unidad 5. Valvulopatías cardiacas</strong>\r\n<ul>\r\n 	<li>Tema 1. Valvulopatía mitral</li>\r\n 	<li>Tema 2. Valvulopatía tricuspídea</li>\r\n 	<li>Tema 3. Valvulopatía aórtica</li>\r\n 	<li>Tema 4. Valvulopatía pulmonar</li>\r\n</ul>\r\n<strong>Unidad 6. Insuficiencia cardiaca</strong>\r\n<ul>\r\n 	<li>Tema 1. Aspectos generales de la insuficiencia cardiaca</li>\r\n 	<li>Tema 2. Diagnóstico y tratamiento de la insuficiencia cardiaca crónica</li>\r\n 	<li>Tema 3. Diagnóstico y tratamiento de la insuficiencia cardiaca aguda</li>\r\n</ul>\r\n<strong>Unidad 7. Cor pulmonale</strong>\r\n<ul>\r\n 	<li>Tema 1. Aspectos generales del <em>cor pulmonale</em></li>\r\n 	<li>Tema 2. Diagnóstico del <em>cor pulmonalec</em></li>\r\n 	<li>Tema 3. Tratamiento del <em>cor pulmonale</em></li>\r\n</ul>\r\n<strong>Unidad 8. Cardiomiopatías</strong>\r\n<ul>\r\n 	<li>Tema 1. Cardiomiopatía dilatada</li>\r\n 	<li>Tema 2. Cardiomiopatía hipertrófica</li>\r\n 	<li>Tema 3. Cardiomiopatía restrictiva</li>\r\n</ul>'),
(534, 116, 'image', ''),
