(601, 131, '_wp_page_template', 'default'),
(602, 131, 'dirigido_a', 'Personal de Enfermería de todos los niveles de atención del IMSS'),
(603, 131, 'acerca', 'El propósito de este curso es capacitar al personal de Enfermería sobre los principales aspectos del sarampión y las intervenciones que se deben realizar para fortalecer las estrategias para el control de esta enfermedad y mejorar la calidad de la atención que se proporciona a la población.'),
(604, 131, 'objetivo', 'Identificar los aspectos generales del sarampión y las intervenciones de Enfermería asociadas con su prevención, a fin de reconocer la importancia de llevarlas a cabo en su práctica profesional para contribuir en la disminución de la morbimortalidad relacionada con esta enfermedad.'),
(605, 131, 'contenido', '1. Sarampión'),
(606, 131, 'image', ''),
(607, 132, '_wp_attached_file', '2026/04/Actualizacion-Sarampion-Enfermeria.jpg'),
