(609, 131, '_thumbnail_id', '132'),
(610, 133, '_wp_page_template', 'default'),
(611, 133, 'dirigido_a', 'Médicos familiares, médico no familiar especialista en Medicina de Rehabilitación, personal de Terapia Física y Rehabilitación, personal de Terapia Ocupacional, personal de Enfermería'),
(612, 133, 'acerca', 'La carga de los sistemas de salud generada por la COVID-19 no sólo se debe a la atención del evento agudo, sino también a la cronicidad de la misma. \nSe sabe que ésta es una enfermedad multisistémica con afectaciones a diversos niveles, sin embargo, el sistema respiratorio continúa siendo la principal fuente de infección y lesión, con consecuencias a largo plazo. Aquí es donde radica la importancia de distinguir los elementos necesarios para otorgar rehabilitación respiratoria a la población afectada.\nPor tal motivo, la Dirección de Prestaciones Médicas del Instituto Mexicano del Seguro Social (IMSS), a través de la Coordinación de Educación en Salud, pone a su disposición el curso: Rehabilitación respiratoria en pacientes pos-COVID-19, a fin de que distinga sus componentes y los aplique en su práctica profesional.');
INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(613, 133, 'objetivo', 'Identificar los elementos para proporcionar rehabilitación respiratoria en pacientes pos-COVID-19, a fin de utilizarlos en la atención oportuna de esta población.'),
(614, 133, 'contenido', '<strong>Unidad Rehabilitación respiratoria en pacientes pos-COVID-19 en el IMSS </strong>\n<ul>\n 	<li>Tema 1. Sistema respiratorio y COVID-19</li>\n 	<li>Tema 2. Evaluación de pacientes con sospecha de secuelas respiratorias por COVID-19</li>\n 	<li>Tema 3. Tratamiento de pacientes con secuelas respiratorias de COVID-19</li>\n</ul>'),
(615, 133, 'image', 'Rehabilitacion-Respiratoria-posCOVID19.jpg'),
(616, 134, '_wp_page_template', 'default'),
(617, 134, 'dirigido_a', 'Personal y médicos residentes de los tres niveles de atención involucrados en la atención del paciente'),
(618, 134, 'acerca', 'Hoy en día, el SARS-CoV-2 se ha extendido a cientos de países, ocasionando miles de casos de COVID-19, por lo que la Organización Mundial de la Salud la ha catalogado como una pandemia.\nEs por ello que el Instituto Mexicano del Seguro Social, a través de la Dirección de Prestaciones Médicas, pone a disposición del personal de salud el curso Enfermedad por coronavirus 2019 (COVID-19), en el cual se estudiarán los principales aspectos de la prevención, diagnóstico y tratamiento de esta enfermedad, a fin de fortalecer sus competencias profesionales para afrontar esta situación emergente'),
(619, 134, 'objetivo', 'Identificar los principales aspectos de la enfermedad por coronavirus 2019, a fin de utilizarlos en su práctica cotidiana en beneficio propio y de la población usuaria de los servicios de salud que ofrece el IMSS.'),
(620, 134, 'contenido', 'UNIDAD 1. Aspectos generales de la COVID-19\nUNIDAD 2. Prevención y control del SARS-COV-2\nUNIDAD 3. Atención de pacientes con sospecha- confirmación de COVID-19'),
(621, 134, 'image', ''),
(622, 135, '_wp_attached_file', '2026/04/Enfermedad-Coronavirus-2019.jpg'),
