(654, 140, '_thumbnail_id', '141'),
(655, 142, '_wp_page_template', 'default'),
(656, 142, 'dirigido_a', 'Personal médico, de Enfermería y de rehabilitación adscrito a los tres niveles de atención del IMSS'),
(657, 142, 'acerca', 'La presente estrategia educativa pretende coadyuvar las actividades de capacitación a distancia que tiene el Instituto y presenta los antecedentes, desarrollo y la manera de aplicación de los diferentes programas de rehabilitación cardiaca para beneficio de los derechohabientes con cardiopatía.'),
(658, 142, 'objetivo', 'Aplicar los conocimientos fundamentales de rehabilitación cardíaca para establecer un programa de tratamiento de rehabilitación para pacientes con patología cardiovascular.'),
(659, 142, 'contenido', '1. Introducción a la rehabilitación cardíaca\r\n2. Estratificación del riesgo cardiovascular y rehabilitación\r\n3. Fisiología y prescripción del ejercicio\r\n4. Factores de riesgo cardiovascular\r\n5. Programas de rehabilitación cardíaca'),
(660, 142, 'image', 'Rehabilitacion-cardiovascular-prevencion.jpg'),
(661, 143, '_wp_page_template', 'default'),
(662, 143, 'dirigido_a', 'Personal médico adscrito al primer nivel de atención del IMSS'),
(663, 143, 'acerca', 'El propósito de este curso es capacitar al personal médico con conocimientos actualizados sobre los principales motivos de consulta ginecológica en atención primaria para proporcionar un servicio médico integral y de calidad a la población usuaria.'),
(664, 143, 'objetivo', 'Establecer estrategias de prevención, diagnóstico y tratamiento para las pacientes que solicitan atención médica por motivos de índole ginecológica, a fin de mejorar su salud y calidad de vida.'),
(665, 143, 'contenido', '1. Fundamentos de ginecología\r\n2. Alteraciones benignas de la glándula mamaria\r\n3. Patología benigna de ovario\r\n4. Infecciones vaginales\r\n5. Patología benigna vulvar\r\n6. Dolor abdominal ginecológico\r\n7. Sangrado uterino anormal\r\n8. Incontinencia urinaria y prolapso de órganos pélvicos\r\n9. Climaterio y menopausia'),
(666, 143, 'image', ''),
(667, 144, '_wp_attached_file', '2026/04/Actualizacion-ginecologia.jpg'),
