(693, 148, '_thumbnail_id', '149'),
(694, 150, '_wp_page_template', 'default'),
(695, 150, 'dirigido_a', 'Personal de Estadística, Archivo Clínico y Codificación Clínica, médicos residentes de primer año del IMSS'),
(696, 150, 'acerca', 'La Clasificación Internacional de Enfermedades (CIE) incluye miles de códigos que se utilizan en todo el mundo. Esta herramienta permite contar con un panorama más preciso sobre el estado de salud de la población y del impacto de las estrategias empleadas para dar respuesta a las necesidades de la población en este campo. \r\n\r\nPor lo anterior, el presente curso tiene como finalidad proporcionarle los conocimientos básicos para el empleo correcto de la CIE-10, con objeto de obtener información conveniente y detallada que permita la toma de decisiones oportuna y orientada.'),
(697, 150, 'objetivo', 'Utilizar de manera adecuada los volúmenes de la CIE-10 para realizar la correcta codificación de los diagnósticos médicos.'),
(698, 150, 'contenido', '1. Fundamentos de la codificación clínica\r\n2. Morbilidad (aplicación de las reglas de la MB1-MB5)\r\n3. Morbilidad (volumen 3 y 1)'),
(699, 150, 'image', 'Codificacion-clinica-basica.jpg'),
(700, 151, '_wp_attached_file', '2026/04/Codificacion-clinica-basica.jpg'),
(701, 151, '_wp_attachment_metadata', 'a:6:{s:5:\"width\";i:1732;s:6:\"height\";i:631;s:4:\"file\";s:39:\"2026/04/Codificacion-clinica-basica.jpg\";s:8:\"filesize\";i:72106;s:5:\"sizes\";a:5:{s:6:\"medium\";a:5:{s:4:\"file\";s:39:\"Codificacion-clinica-basica-300x109.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:109;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:6321;}s:5:\"large\";a:5:{s:4:\"file\";s:40:\"Codificacion-clinica-basica-1024x373.jpg\";s:5:\"width\";i:1024;s:6:\"height\";i:373;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:40707;}s:9:\"thumbnail\";a:5:{s:4:\"file\";s:39:\"Codificacion-clinica-basica-150x150.jpg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:4274;}s:12:\"medium_large\";a:5:{s:4:\"file\";s:39:\"Codificacion-clinica-basica-768x280.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:280;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:26168;}s:9:\"1536x1536\";a:5:{s:4:\"file\";s:40:\"Codificacion-clinica-basica-1536x560.jpg\";s:5:\"width\";i:1536;s:6:\"height\";i:560;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:72995;}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}'),
(702, 150, '_thumbnail_id', '151'),
(703, 152, '_wp_page_template', 'default'),
(704, 152, 'dirigido_a', 'Personal de Enfermería de los tres niveles de atención.'),
(705, 152, 'acerca', 'El profesional de Enfermería administra medicamentos por diferentes vías en la población derechohabiente. Si bien esta acción es una de las intervenciones propias del personal de Enfermería, en algunas ocasiones surge la interrogante o desconocimiento sobre algunos aspectos inherentes a este procedimiento, tales como la dosis, diluyente, vía y tiempo de ministración, entre otros.\r\n\r\nPor tal motivo, la Dirección de Prestaciones Médicas del IMSS, a través de la Coordinación de Educación en Salud, pone a su disposición el curso Farmacología básica para Enfermería, a fin de que distinga los aspectos farmacológicos de los grupos de medicamentos de mayor uso, para que aplique estos conocimientos en su práctica profesional.'),
(706, 152, 'objetivo', 'Aplicar las bases farmacológicas y normativas para la administración de medicamentos, a fin de evitar errores por medicación durante la práctica profesional.'),
(707, 152, 'contenido', '<ol>\r\n 	<li>Introducción a la farmacología</li>\r\n 	<li>Marco regulatorio para la administración de medicamentos</li>\r\n 	<li>Soluciones intravenosas</li>\r\n 	<li>Uso de AINE ante el dolor, la inflamación y la fiebre en la atención de Enfermería</li>\r\n 	<li>Función gastrointestinal</li>\r\n 	<li>Fármacos antimicrobianos: antibióticos y antivirales</li>\r\n 	<li>Fármacos antimicrobinos: antiparasitarios y antimicóticos</li>\r\n 	<li>Función cardiovascular: antihipertensivos y antiarrítmicos</li>\r\n 	<li>Fármacos que actúan en la coagulación e hipolipemiantes</li>\r\n 	<li>Fármacos hipoglucemiantes</li>\r\n</ol>'),
(708, 152, 'image', ''),
(709, 153, '_wp_attached_file', '2026/04/farmacologia-enfermeria-2-scaled-1.jpg'),
