(756, 161, '_thumbnail_id', '162'),
(757, 163, '_wp_page_template', 'default'),
(758, 163, 'dirigido_a', 'Personal de Enfermería adscrito a las Unidades del segundo y tercer nivel de atención con las siguientes categorías: auxiliar de Enfermería, personal de Enfermería general, personal de Enfermería especialista, personal de enfermería como jefes de piso y subjefes de Enfermería'),
(759, 163, 'acerca', 'La terapia de infusión intravascular es el procedimiento invasivo que se utiliza con más frecuencia en los servicios hospitalarios, debido a que es imprescindible en el tratamiento del paciente hospitalizado, sobre todo en pacientes en estado crítico con padecimientos crónicos o con terapias oncológicas.'),
(760, 163, 'objetivo', 'Aplicar cuidados de Enfermería a los pacientes con dispositivos de acceso vascular y terapia de infusión intravascular, a fin de disminuir riesgos y complicaciones durante su administración en la población usuaria.');
INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(761, 163, 'contenido', '<ol>\r\n 	<li>Introducción a la terapia de infusión intravascular</li>\r\n 	<li>Marco normativo para la administración de la terapia de infusión intravascular</li>\r\n 	<li>Humanismo en la terapia de infusión intravascular</li>\r\n 	<li>Anatomía y fisiología para la terapia de infusión intravascular</li>\r\n 	<li>Tipos de Dispositivos de Acceso Vascular (DAV)</li>\r\n 	<li>Seguridad del paciente con terapia de infusión intravascular</li>\r\n 	<li>Complicaciones en los accesos vasculares y en la terapia de infusión intravascular</li>\r\n 	<li>Atención de Enfermería a neonatos y pediátricos con terapia de infusión</li>\r\n 	<li>Terapia de infusión intravascular en el adulto</li>\r\n 	<li>Vigilancia epidemiológica de las Infecciones Asociadas a la Atención de la Salud (IAAS)</li>\r\n</ol>'),
(762, 163, 'image', ''),
(763, 164, '_wp_attached_file', '2026/04/Atencion-enfermeria-accesos-vasculares.jpg'),
