(765, 163, '_thumbnail_id', '164'),
(766, 165, '_wp_page_template', 'default'),
(767, 165, 'dirigido_a', 'Personal de salud que realice actividades docentes en el IMSS'),
(768, 165, 'acerca', 'El propósito de este curso es capacitar al personal de salud que realiza actividades docentes dentro del instituto con conocimientos sobre el diseño de instrumentos de evaluación y elementos para mejorar de manera continua el proceso enseñanza-aprendizaje, a fin de que los utilice en su práctica para beneficio de sí mismo, sus alumnos, las instituciones y la sociedad en general.'),
(769, 165, 'objetivo', 'Diseñar los instrumentos de evaluación que requiere para obtener información pertinente y relevante sobre las necesidades, avances y los logros de aprendizaje de sus alumnos, a fin de llevar a cabo una toma de decisiones efectiva respecto a las acciones a realizar para mejorar el aprovechamiento del alumno o determinar su promoción o acreditación al finalizar su proceso de formación.'),
(770, 165, 'contenido', '1. Instrumentos para la evaluación del contenido conceptual y factual\r\n2. Instrumentos para la evaluación del contenido procedimental\r\n3. Instrumentos para la evaluación del contenido actitudinal\r\n4. Instrumentos para la evaluación del contenido actitudinal\r\n5. Análisis de resultados y mejora continua'),
(771, 165, 'image', 'Instrumentos-Evaluacion-Aprendizaje.jpg'),
(772, 166, '_wp_page_template', 'default'),
(773, 166, 'dirigido_a', 'Personal médico de primer nivel de atención del IMSS'),
(774, 166, 'acerca', 'El presente curso pretende capacitar al personal médico para que cuente con las herramientas necesarias para la prevención y diagnóstico oportuno de ésta y otras enfermedades urológicas.\r\nCabe señalar que el presente curso otorga puntos curriculares aplicables al proceso de certificación vigente (recertificación) del Consejo Mexicano de Certificación de Medicina Familiar A.C.'),
(775, 166, 'objetivo', 'Reconocer los factores de riesgo y las estrategias de prevención y diagnóstico de las enfermedades urológicas más frecuentes en el primer nivel de atención, a fin de establecer un plan de tratamiento adecuado para cada caso.'),
(776, 166, 'contenido', '<ol>\r\n 	<li>Hiperplasia prostática benigna</li>\r\n 	<li>Urolitiasis</li>\r\n 	<li>Epididimitis, orquitis y orquiepididimitis</li>\r\n 	<li>Disfunción eréctil</li>\r\n 	<li>Neoplasias del tracto urogenital</li>\r\n 	<li>Trastornos de los genitales externos</li>\r\n</ol>'),
(777, 166, 'image', 'Prevencion-diagnostico-cancer-prostata.jpg'),
(778, 167, '_wp_attached_file', '2026/04/Prevencion-diagnostico-cancer-prostata.jpg'),
