(781, 168, '_wp_page_template', 'default'),
(782, 168, 'dirigido_a', 'Personal médico familiar, médico no familiar, residentes del IMSS y directivos médicos.'),
(783, 168, 'acerca', 'El propósito de este curso es capacitar al personal médico con conocimientos básicos sobre economía de la salud para que puedan aplicarlos en su práctica profesional.'),
(784, 168, 'objetivo', 'Identificar los elementos de la economía de la salud y su relación con la práctica médica a fin de reconocer su importancia en los procesos de atención en los sistemas de salud.'),
(785, 168, 'contenido', '<ol>\r\n 	<li>Introducción a la economía de la salud</li>\r\n 	<li>Oferta de servicios de salud</li>\r\n 	<li>Costos de producción en los servicios de salud</li>\r\n 	<li>Evaluación económica en salud</li>\r\n 	<li>Demanda de servicios de salud</li>\r\n</ol>'),
