(791, 170, 'dirigido_a', 'Personal médico y de Enfermería relacionado con procedimientos quirúrgicos de segundo y tercer nivel de atención del IMSS'),
(792, 170, 'acerca', 'El propósito de este curso es presentar una serie de lineamientos encaminados a minimizar la probabilidad de ocurrencia de errores o eventos adversos con el objetivo de incrementar la seguridad del paciente.'),
(793, 170, 'objetivo', 'Aplicar acciones encaminadas a mantener la seguridad del paciente que requiere tratamiento quirúrgico a fin de prevenir la ocurrencia de eventos adversos.'),
(794, 170, 'contenido', '1. Prevalencia de eventos adversos en cirugía\r\n2. Medidas para mejorar la seguridad del paciente en cirugía\r\n3. Protocolo universal de procedimientos quirúrgicos y de alto riesgo'),
(795, 170, 'image', 'Prevencion-eventos-adversos.jpg'),
(796, 171, '_wp_page_template', 'default'),
(797, 171, 'dirigido_a', 'Enfermeras y enfermeros auxiliares, generales, especialistas y jefes de piso, de los tres niveles de atención del IMSS'),
(798, 171, 'acerca', 'Los aspectos generales de la tanatología, las pérdidas y el duelo en las diferentes etapas de la vida, la calidad de vida en el paciente terminal, los cuidados paliativos y las intervenciones de Enfermería en el acompañamiento del paciente terminal y de su familia.'),
(799, 171, 'objetivo', 'Distinguir las estrategias que debe considerar el profesional de Enfermería para proporcionar apoyo tanatológico al paciente en estado terminal y su familia, a fin de mejorar su calidad de vida durante este periodo.'),
(800, 171, 'contenido', '<ol>\r\n 	<li>Generalidades de la tanatología</li>\r\n 	<li>Pérdidas, muerte y duelo en las diferentes etapas de la vida</li>\r\n 	<li>Calidad de vida en el paciente terminal</li>\r\n 	<li>Cuidados paliativos</li>\r\n 	<li>Enfermería en el acompañamiento del paciente terminal</li>\r\n 	<li>Enfermería en el acompañamiento de la familia del paciente terminal</li>\r\n 	<li>La familia y el cuidador primario ante la enfermedad terminal y la muerte</li>\r\n 	<li>Aspectos éticos y legales sobre el proceso de morir y la muerte</li>\r\n 	<li>El profesional de Enfermería ante la muerte</li>\r\n</ol>'),
