(814, 175, '_wp_page_template', 'default'),
(815, 175, 'dirigido_a', 'Personal de Enfermería adscrito a Unidades Médicas de Atención Ambulatoria (UMAA), segundo y tercer nivel de atención'),
(816, 175, 'acerca', 'El propósito de este curso es capacitar a todo el personal de Enfermería con conocimientos actualizados sobre los cuidados que se deben proporcionar a las y los pacientes con cáncer, a fin de fortalecer su práctica profesional y mejorar la calidad del servicio que se otorga a la población usuaria.'),
(817, 175, 'objetivo', 'Identificar los cuidados de Enfermería que se deben otorgar a los pacientes con cáncer, a fin de aplicarlos en su práctica profesional para contribuir en la eficiencia y calidad de la atención a la salud de esta población.'),
(818, 175, 'contenido', '<ol>\r\n 	<li>Principios de oncología y atención de Enfermería</li>\r\n 	<li>Cuidados de Enfermería en pacientes con cáncer sometidos a cirugía</li>\r\n 	<li>Cuidados de Enfermería en pacientes con cáncer sometidos a radioterapia</li>\r\n 	<li>Cuidados de Enfermería en pacientes con cáncer sometidos a quimioterapia</li>\r\n 	<li>Fármacos quimioterapéuticos</li>\r\n 	<li>Cuidados de Enfermería ante la toxicidad del tratamiento oncológico</li>\r\n 	<li>Intervenciones de Enfermería en la seguridad del paciente con tratamiento oncológico</li>\r\n 	<li>Cuidados de Enfermería en urgencias oncológicas</li>\r\n 	<li>Cuidados paliativos en el paciente con cáncer en situación terminal</li>\r\n 	<li>Aspectos complementarios del rol de Enfermería en el cuidado de pacientes con cáncer</li>\r\n</ol>'),
(819, 175, 'image', ''),
