(868, 186, '_wp_page_template', 'default'),
(869, 186, 'dirigido_a', 'Personal de Enfermería del IMSS involucrado en la atención de mujeres en edad reproductiva durante la fase preconcepcional, embarazo, parto y puerperio'),
(870, 186, 'acerca', 'El curso propone una ruta que va desde la atención preconcepcional, el control durante el embarazo, hasta el puerperio, con base en intervenciones que el profesional de enfermería deberá otorgar para detectar riesgos y evitar complicaciones que pongan en peligro la vida del binomio.'),
(871, 186, 'objetivo', 'Aplicar los cuidados de Enfermería que contribuyan a la salud materno-fetal, desde la preconcepción, embarazo, parto y puerperio, para mejorar la calidad de vida de la mujer.'),
(872, 186, 'contenido', '<ol>\r\n 	<li>Aspectos generales de la salud materna</li>\r\n 	<li>Atención preconcepcional de Enfermería</li>\r\n 	<li>Intervención de Enfermería en la vigilancia prenatal</li>\r\n 	<li>Atención de Enfermería en el embarazo patológico</li>\r\n 	<li>Cuidados de Enfermería durante las emergencias obstétricas</li>\r\n 	<li>Cuidados de Enfermería en el puerperio</li>\r\n 	<li>Atención de Enfermería en el puerperio patológico</li>\r\n</ol>'),
