(876, 186, '_thumbnail_id', '187'),
(877, 188, '_wp_page_template', 'default'),
(878, 188, 'dirigido_a', 'Personal médico del primer nivel de atención.'),
(879, 188, 'acerca', 'La presente estrategia educativa pretende capacitar al personal médico con conocimientos actualizados para la atención de las y los pacientes con patologías cutáneas que se presentan con mayor frecuencia en el primer nivel de atención a fin de que pueda establecer el diagnóstico temprano y el tratamiento oportuno para reducir el riesgo de complicaciones.'),
(880, 188, 'objetivo', 'Establecer el diagnóstico temprano de las patologías cutáneas más frecuentes para implementar el tratamiento oportuno que permita disminuir el riesgo de complicaciones.'),
(881, 188, 'contenido', '1. Aspectos generales de la dermatología\n2. Dermatitis atópica y por contacto\n3. Dermatosis eritematoescamosas\n4. Enfermedades infecciosas más frecuentes de la piel\n5. Acné\n6. Cáncer de piel'),
(882, 188, 'image', 'Actualizacion-Dermatologia.jpg'),
(883, 189, '_wp_attached_file', '2026/04/actualizavion_dermatologia-scaled-1.jpg'),
