(910, 195, '_wp_page_template', 'default'),
(911, 195, 'dirigido_a', 'Personal de salud involucrado en actividades docentes en el IMSS que actualmente participa o desea participar en educación a distancia'),
(912, 195, 'acerca', 'El propósito de este curso es que el personal de salud involucrado en actividades docentes desarrolle las competencias necesarias relacionadas con los elementos, componentes y la metodología de la educación a distancia para que la considere como una opción educativa eficaz para generar recursos humanos calificados mediante la incorporación de las tecnologías de la información y comunicación.'),
(913, 195, 'objetivo', 'Fundamentar la importancia de la educación a distancia mediante la elaboración de propuestas que incorporen sus elementos, componentes y metodología a fin de presentar soluciones a las necesidades de aprendizaje de su entorno educativo.'),
(914, 195, 'contenido', '<ol>\r\n 	<li>Evolución e implicaciones de la tecnología en la educación y capacitación a distancia</li>\r\n 	<li>La educación a distancia</li>\r\n 	<li>Modalidades educativas a distancia</li>\r\n 	<li>Roles en la educación a distancia</li>\r\n 	<li>Ambientes virtuales de aprendizaje</li>\r\n 	<li>Evaluación del aprendizaje en la educación a distancia</li>\r\n</ol>'),
(915, 195, 'image', 'Formacion-Educacion-Distancia-TC.jpg'),
(916, 196, '_wp_page_template', 'default'),
(917, 196, 'dirigido_a', 'Personal médico adscrito al primer nivel de atención');
INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(918, 196, 'acerca', 'El embarazo es un proceso fisiológico en el que existen modificaciones anatómicas y funcionales que incrementan los requerimientos sanguíneos, energéticos, hormonales y de otras sustancias útiles para el desarrollo de la unidad fetoplacentaria; para que este evento fisiológico sea favorable, se requiere de una adaptación del organismo materno, la cual puede contribuir a la aparición de ciertas complicaciones en esta etapa.  \r\n\r\nEste escenario denota que es imprescindible el control prenatal con enfoque de riesgo para identificar, desde la primera consulta, los factores que incrementan el desarrollo de patologías en este proceso, lo cual permitirá un diagnóstico, tratamiento una referencia oportuna (en caso necesario) y, por lo tanto, una reducción en la morbimortalidad materna. \r\n\r\nPor tal motivo, la Dirección de Prestaciones Médicas, a través de la Coordinación de Educación en Salud, pone a su disposición el curso Control prenatal con enfoque de riesgo, a fin de dotarle de herramientas para otorgar una atención integral y de calidad a la gestante en el primer nivel de atención.'),
(919, 196, 'objetivo', 'Personal médico adscrito al primer nivel de atención.'),
(920, 196, 'contenido', 'Unidad 1. Generalidades en atención prenatal con enfoque de riesgo\r\nUnidad 2. Vigilancia del embarazo en la consulta externa\r\nUnidad 3. Enfermedades asociadas al embarazo\r\nUnidad 4.Educación de la embarazada'),
(921, 196, 'image', 'Control-Prenatal-Enfoque-Riesgo.jpg'),
(922, 197, '_wp_attached_file', '2026/04/control_prenatal_aprobada.jpg'),
(923, 197, '_wp_attachment_metadata', 'a:6:{s:5:\"width\";i:1732;s:6:\"height\";i:631;s:4:\"file\";s:37:\"2026/04/control_prenatal_aprobada.jpg\";s:8:\"filesize\";i:255603;s:5:\"sizes\";a:5:{s:6:\"medium\";a:5:{s:4:\"file\";s:37:\"control_prenatal_aprobada-300x109.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:109;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:4187;}s:5:\"large\";a:5:{s:4:\"file\";s:38:\"control_prenatal_aprobada-1024x373.jpg\";s:5:\"width\";i:1024;s:6:\"height\";i:373;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:24220;}s:9:\"thumbnail\";a:5:{s:4:\"file\";s:37:\"control_prenatal_aprobada-150x150.jpg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:2464;}s:12:\"medium_large\";a:5:{s:4:\"file\";s:37:\"control_prenatal_aprobada-768x280.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:280;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:15640;}s:9:\"1536x1536\";a:5:{s:4:\"file\";s:38:\"control_prenatal_aprobada-1536x560.jpg\";s:5:\"width\";i:1536;s:6:\"height\";i:560;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:44547;}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}'),
(924, 196, '_thumbnail_id', '197'),
(925, 198, '_wp_page_template', 'default'),
(926, 198, 'dirigido_a', 'Este diplomado es nominativo; la propuesta y el registro de alumnos son llevados a cabo de manera exclusiva por las autoridades de Educación de las OOAD y UMAE.\r\n\r\nTodo el personal de salud que desarrolla actividades docentes en el IMSS (médicos, enfermeras, trabajadoras sociales, psicólogos, estomatólogos, nutricionistas y técnicos en el área de la salud)'),
(927, 198, 'acerca', 'El Diplomado de profesionalización docente para la educación en salud tiene un enfoque basado en competencias profesionales y los contenidos curriculares están orientados a promover la vinculación de la práctica asistencial con la educativa, mediante el uso de las tecnologías de la información y comunicación para lograr el desarrollo de competencias profesionales que permitan al alumno la  transferencia y aplicación de conocimientos en cada una de las áreas en que se desenvuelven.'),
(928, 198, 'objetivo', 'Fundamentar su práctica educativa en principios, técnicas y estrategias que promuevan el aprendizaje de sus alumnos con un sentido ético y enfocado al desarrollo de sus potencialidades a lo largo de la vida, a fin de formar profesionales capaces de responder a las necesidades propias de su ámbito profesional y personal.'),
(929, 198, 'contenido', 'Unidad 1. La profesionalización docente\r\nUnidad 2. El docente y el aprendizaje\r\nUnidad 3. Comunicación educativa\r\nUnidad 4. Autoconocimiento y estilos de aprendizaje\r\nUnidad 5. Funciones y operaciones mentales\r\nUnidad 6. Habilidades del pensamiento\r\nUnidad 7. Aprender a aprender\r\nUnidad 8. Planificación educativa\r\nUnidad 9. Diagnóstico de necesidades de formación\r\nUnidad 10. Análisis de necesidades educativas\r\nUnidad 11. Planeación didáctica I\r\nUnidad 12. Planeación didáctica II\r\nUnidad 13. Planeación didáctica III\r\nUnidad 14. Planeación didáctica IV\r\nUnidad 15. Ética y docencia'),
(930, 198, 'image', 'Diplomado-Profesionalizacion-Docente.jpg'),
(931, 199, '_wp_page_template', 'default'),
(932, 199, 'dirigido_a', 'Personal médico de primer nivel de atención del IMSS'),
(933, 199, 'acerca', 'Desde hace varias décadas, la Organización Mundial de la Salud (OMS) reportó que una de las principales causas de morbimortalidad en el mundo son los traumatismos. Estas entidades nosológicas son consideradas un grave problema de salud pública debido a los altos costos sociales y económicos que representan.\n\nEn México, los traumatismos ocupan el cuarto lugar como causa de muerte en la población general y la primera en personas económicamente activas. Lo anterior representa un desafío para los servicios de salud, pues se requiere Personal Médico capacitado para atender a los pacientes afectados.'),
(934, 199, 'objetivo', 'Establecer el diagnóstico y tratamiento de los principales traumatismos que se presentan en el primer nivel de atención, a fin de mejorar el pronóstico de los pacientes y disminuir el riesgo de complicaciones.'),
(935, 199, 'contenido', '<ol>\n 	<li>Traumatismos de cabeza y macizo facial</li>\n 	<li>Traumatismos de tórax</li>\n 	<li>Traumatismos de hombro</li>\n 	<li>Traumatismos de extremidades superiores</li>\n 	<li>Traumatismos de la porción proximal y diafisiaria del fémur</li>\n 	<li>Fracturas de rótula y tibia</li>\n 	<li>Fracturas de tobillo y pie</li>\n 	<li>Esguinces</li>\n</ol>'),
(936, 199, 'image', 'Diagnostico-Principales-Traumatismos.jpg'),
(937, 200, '_wp_attached_file', '2026/04/traumatismos-scaled-1.jpg'),
