(1111, 236, '_wp_page_template', 'default'),
(1112, 236, 'dirigido_a', 'Personal médico de los tres niveles de atención del Instituto Mexicano del Seguro Social.'),
(1113, 236, 'acerca', 'La incidencia mundial de la hemofilia A se estima en 1:5,000 y la hemofilia B de 1:30,000 habitantes hombres. La Federación Mundial de la Hemofilia considera que en los 77 países de los que tiene registro, actualmente hay más de 150,000 personas con este padecimiento. Se calcula que existen alrededor de 400 mil personas con HH en todo el mundo. La Federación de Hemofilia de la República Mexicana (FHRM) tiene registrados aproximadamente 5,512 personas con HH.\r\n\r\nAnte esta problemática, el IMSS ha desarrollado un Protocolo de Atención Integral (PAI) en el que se establecen pautas de actuación del personal de salud de los tres niveles de atención, a fin de homologar las actividades referentes a la atención integral de pacientes con hemofilia hereditaria.  \r\n\r\nPor tal motivo, la Dirección de Prestaciones Médicas del IMSS, a través de la Coordinación de Educación en Salud, pone a su disposición el curso PAI Hemofilia Hereditaria para el personal de Enfermería, a fin de realizar las acciones correspondientes con su ámbito de competencia en beneficio de la población.'),
(1114, 236, 'objetivo', 'Utilizar el Protocolo de Atención Integral Hemofilia Hereditaria en su práctica profesional, a fin de homologar las actividades del equipo multidisciplinario de salud en los diferentes niveles de atención.'),
(1115, 236, 'contenido', '<ul>\r\n 	<li>Tema 1 Promoción de la salud</li>\r\n 	<li>Tema 2 Diagnóstico</li>\r\n 	<li>Tema 3 Tratamiento</li>\r\n 	<li>Tema 4 Atención de complicaciones musculoesqueléticas</li>\r\n 	<li>Tema 5 Atención materna y salud reproductiva</li>\r\n 	<li>Tema 6 Rehabilitación</li>\r\n</ul>'),
(1116, 236, 'image', ''),
