(1174, 250, '_wp_page_template', 'default'),
(1175, 250, 'dirigido_a', 'Personal médico de atención primaria que labora en el IMSS.'),
(1176, 250, 'acerca', 'El propósito de este curso de formación es proporcionar al personal médico de atención primaria conocimientos actualizados sobre el diagnóstico y tratamiento de las enfermedades gastrointestinales que son causa de morbimortalidad y son motivos comunes de consulta en el primer nivel de atención. \r\nPor medio de este curso, el personal médico de atención primaria desarrollará las competencias necesarias para abordar los desafíos que se le presentan en su práctica diaria, lo cual le facultará para brindar servicios de atención médica de alta calidad.'),
(1177, 250, 'objetivo', 'Implementar estrategias de prevención, diagnóstico oportuno y tratamiento de las enfermedades gastrointestinales que son más comunes en el primer nivel de atención para reducir tanto su incidencia como las complicaciones asociadas, contribuyendo así a mejorar la salud de las personas que presentan estas afecciones.');
INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(1178, 250, 'contenido', '<ul>\r\n 	<li><strong>Unidad 1</strong> Gastritis y duodenitis</li>\r\n 	<li><strong>Unidad 2</strong> Dispepsia funcional</li>\r\n 	<li><strong>Unidad 3</strong> Enfermedades infecciosas intestinales</li>\r\n 	<li><strong>Unidad 4</strong> Síndrome de intestino irritable</li>\r\n 	<li><strong>Unidad 5</strong> Trastornos hepatobiliares</li>\r\n</ul>'),
