(1183, 252, '_wp_page_template', 'default'),
(1184, 252, 'dirigido_a', 'Personal médico de atención primaria que labora en el Instituto Mexicano del Seguro Social.'),
(1185, 252, 'acerca', 'El propósito de este curso es capacitar al personal médico de atención primaria con conocimientos actualizados en las diversas áreas de la medicina, particularmente en aquellos relacionados con otras enfermedades que son motivo de consulta frecuente en el primer nivel de atención.\r\nPor medio de este curso, el personal médico de atención primaria desarrollará las competencias genéricas indispensables para afrontar los retos que se presentan en su práctica cotidiana, lo cual le permitirá ofrecer un servicio de atención médica de excelencia y calidad en beneficio de los usuarios del Instituto Mexicano del Seguro Social.'),
(1186, 252, 'objetivo', 'Implementar estrategias de prevención, diagnóstico y tratamiento de entidades nosológicas que son motivo frecuente de atención en el primer nivel de atención para disminuir su incidencia o sus complicaciones, a fin de mejorar la salud de los usuarios del Instituto Mexicano del Seguro Social.'),
(1187, 252, 'contenido', '<ul>\r\n 	<li><strong>Unidad 1</strong> Intoxicaciones y envenenamientos</li>\r\n 	<li><strong>Unidad 2</strong> Dermatitis más frecuente</li>\r\n 	<li><strong>Unidad 3</strong> Micosis</li>\r\n 	<li><strong>Unidad 4</strong> Traumatismos más frecuentes</li>\r\n</ul>'),
