(1192, 254, '_wp_page_template', 'default'),
(1193, 254, 'dirigido_a', 'Personal de Enfermería de los tres niveles de atención.'),
(1194, 254, 'acerca', 'Las intervenciones del profesional de Enfermería son de vital importancia para la prevención, detección y tratamiento de las posibles complicaciones durante las enfermedades cardiovasculares.\r\nPara ello, es imprescindible la aplicación continua del proceso de atención de Enfermería para que se realicen intervenciones encaminadas a prevenir complicaciones o bien, en caso de presentarse éstas, se priorice la atención del paciente con enfermedad cardiovascular de manera sistematizada.\r\nPor tal motivo, la Dirección de Prestaciones Médicas del Instituto Mexicano del Seguro Social (IMSS), a través de la Coordinación de Educación en Salud, pone a su disposición el curso Intervenciones de Enfermería en pacientes con enfermedades cardiovasculares, a fin de que distinga las acciones que lo conforman y las aplique en su práctica profesional.'),
(1195, 254, 'objetivo', 'Distinguir las intervenciones de Enfermería en adultos con enfermedades cardiovasculares, a fin de aplicarlas para proporcionar una atención integral a esta población.'),
(1196, 254, 'contenido', '<ul>\r\n 	<li><strong>Unidad 1.</strong> Fundamentos para la atención de pacientes con enfermedades cardiovasculares</li>\r\n 	<li><strong>Unidad 2. </strong>Hipertensión arterial sistémica</li>\r\n 	<li><strong>Unidad 3.</strong> Infarto agudo de miocardio</li>\r\n 	<li><strong>Unidad 4.</strong> Evento vascular cerebral</li>\r\n 	<li><strong>Unidad 5.</strong> Insuficiencia cardiaca</li>\r\n 	<li><strong>Unidad 6.</strong> Insuficiencia venosa crónica</li>\r\n</ul>'),
(1197, 254, 'image', ''),
(1198, 255, '_wp_attached_file', '2026/04/DEPS_carrusel_cardiovasculares.jpg'),
