(1234, 263, '_wp_page_template', 'default'),
(1235, 263, 'dirigido_a', 'Personal médico de los tres niveles de atención del IMSS.'),
(1236, 263, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\n\r\nPor ello, se complace en poner al alcance del personal médico de los tres niveles de atención el curso PAI Cervicalgia para el personal médico, en su modalidad en línea.\r\n\r\nEl propósito de este curso es capacitar al personal médico sobre el Protocolo de Acción Integral (PAI) Cervicalgia, desarrollado por el Instituto para estandarizar acciones de prevención, diagnóstico y tratamiento de pacientes con esta enfermedad.'),
(1237, 263, 'objetivo', 'Utilizar el Protocolo de Atención Integral (PAI) Cervicalgia en su práctica profesional, a fin de homologar las actividades del equipo multidisciplinario de salud en los diferentes niveles de atención.'),
(1238, 263, 'contenido', '<ol>\r\n 	<li>Unidad PAI Cervicalgia</li>\r\n 	<li>Material complementario</li>\r\n</ol>'),
