(1342, 286, '_wp_page_template', 'default'),
(1343, 286, 'dirigido_a', 'Personal médico y de nutrición'),
(1344, 286, 'acerca', 'Se ha demostrado que una intervención nutricional oportuna coadyuva a mejorar el estado general de salud de los pacientes quirúrgicos, politraumatizados, quemados, trasplantados, con VIH-SIDA y de aquéllos con trastornos de la conducta alimentaria. Además, permite aminorar las alteraciones metabólicas que se presentan bajo esas condiciones, evitar complicaciones y lograr una evolución satisfactoria. \r\nPor tal motivo, la Dirección de Prestaciones Médicas, a través de la Coordinación de Educación en Salud, pone a su disposición el curso Nutrición en situaciones especiales, a fin de que adquiera herramientas que le permitan proporcionar los cuidados nutricios que requiere la población con este tipo de afecciones.'),
(1345, 286, 'objetivo', 'Hacer uso del requerimiento calórico y nutrimental de los pacientes en condiciones especiales para organizar una intervención nutricional que les permita mejorar su estado de salud.'),
(1346, 286, 'contenido', '<strong>Unidad 1. Nutrición en el paciente quirúrgico</strong>\r\n<ul>\r\n 	<li>Tema 1. Estado nutricio en el perioperatorio</li>\r\n 	<li>Tema 2. Evaluación nutricional en el paciente quirúgico</li>\r\n 	<li>Tema 3. Tratamiento nutricional en el paciente quirúrgico</li>\r\n</ul>\r\n<strong>Unidad 2. Nutrición en pacientes politraumatizados y quemados</strong>\r\n<ul>\r\n 	<li>Tema 1. Nutrición en pacientes politraumatizados</li>\r\n 	<li>Tema 2. Nutrición en pacientes quemados</li>\r\n</ul>\r\n<strong>Unidad 3. Nutrición en pacientes con trasplante</strong>\r\n<ul>\r\n 	<li>Tema 1. Trasplante de órganos y preparación pretrasplante</li>\r\n 	<li>Tema 2. Cuidado nutricio en el periodo postrasplante</li>\r\n</ul>\r\n<strong>Unidad 4. Nutrición en pacientes con VIH-SIDA</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades de la infección por VIH</li>\r\n 	<li>Tema 2. Tratamiento nutricional en pacientes con VIH-SIDA</li>\r\n</ul>\r\n<strong>Unidad 5. Nutrición en pacientes con trastornos de la conducta alimentaria</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades de los trastornos de la conducta alimentaria</li>\r\n 	<li>Tema 2. Anorexia nerviosa</li>\r\n 	<li>Tema 3. Bulimia nerviosa</li>\r\n 	<li>Tema 4. Trastorno por atracón</li>\r\n</ul>'),
