(1359, 288, '_thumbnail_id', '289'),
(1360, 290, '_wp_page_template', 'default'),
(1361, 290, 'dirigido_a', 'Personal médico y de nutrición'),
(1362, 290, 'acerca', 'La nutrición es uno de los factores que se relaciona de manera significativa con la salud de las personas. En la población infantil y adolescente, una nutrición adecuada favorece el crecimiento y desarrollo, mientras que en la población adulta es fundamental para mantener un estado de salud óptimo y prevenir la génesis de enfermedades crónicas no transmisibles. Por ello, una de las principales actividades que el personal de salud debe realizar es la evaluación del estado nutricional con la finalidad de identificar de manera oportuna las alteraciones y, con base en ello, proporcionar el tratamiento adecuado, así como orientar a la población sobre la dieta y alimentación correctas.\r\n\r\nPor lo anterior, la Dirección de Prestaciones Médicas del Instituto Mexicano del Seguro Social considera fundamental la capacitación del personal de salud en materia de nutrición, la cual permitirá mejorar la calidad de la atención que proporciona a la población usuaria de los servicios de salud.'),
(1363, 290, 'objetivo', 'Identificar las bases para el tratamiento nutricional, a fin de reconocer su importancia y utilizar dichos conocimientos para el tratamiento de la población usuaria de los servicios de salud.'),
(1364, 290, 'contenido', '<strong>Unidad 1 Principios básicos de la nutrición</strong>\r\n<ul>\r\n 	<li>Tema 1. Macronutrimentos</li>\r\n 	<li>Tema 2. Micronutrimentos</li>\r\n 	<li>Tema 3. Agua</li>\r\n</ul>\r\n<strong>Unidad 2 Los alimentos</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades de los alimentos</li>\r\n 	<li>Tema 2. Procesamiento de los alimentos</li>\r\n 	<li>Tema 3. Seguridad alimentaria y conservación de alimentos</li>\r\n</ul>\r\n<strong>Unidad 3 Bases para una alimentación correcta</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades sobre alimentación</li>\r\n 	<li>Tema 2. Alimentación correcta</li>\r\n 	<li>Tema 3. Guías de orientación alimentaria para la población</li>\r\n</ul>\r\n<strong>Unidad 4 Guías de alimentos en la práctica nutricional</strong>\r\n<ul>\r\n 	<li>Tema 1. Sistema Mexicano de Alimentos Equivalentes</li>\r\n 	<li>Tema 2. Guía de Alimentos para la Población Mexicana</li>\r\n 	<li>Tema 3. Cuadro Básico de Alimentos del IMSS</li>\r\n</ul>\r\n<strong>Unidad 5 Evaluación nutricional</strong>\r\n<ul>\r\n 	<li>Tema 1. Historia clínica nutricional</li>\r\n 	<li>Tema 2. Indicadores antropométricos para la evaluación nutricional</li>\r\n 	<li>Tema 3. Indicadores bioquímicos para la evaluación nutricional</li>\r\n 	<li>Tema 4. Indicadores clínicos para la evaluación nutricional</li>\r\n</ul>'),
