(1368, 290, '_thumbnail_id', '291'),
(1369, 292, '_wp_page_template', 'default'),
(1370, 292, 'dirigido_a', 'Personal médico de los tres niveles de atención'),
(1371, 292, 'acerca', 'Desde el 30 de enero del 2020, la COVID-19 fue caracterizada como pandemia debido a sus niveles alarmantes de propagación. Hasta septiembre de 2022 se han reportado a nivel mundial más de 614 millones de casos y más de 6.5 millones de muertes a consecuencia de esta enfermedad. México se encuentra entre los países más afectados, con más de 7 millones de casos y más de 330 mil muertes.\r\n\r\nAnte esta problemática, el Instituto Mexicano del Seguro Social (IMSS) ha desarrollado un Protocolo de Atención Integral (PAI) en el que se establecen pautas de actuación del personal de salud de los tres niveles de atención, a fin de homologar las actividades referentes a la atención integral de pacientes con COVID-19.  \r\n\r\nPor tal motivo, la Dirección de Prestaciones Médicas del IMSS, a través de la Coordinación de Educación en Salud, pone a su disposición el curso Protocolo de Atención Integral COVID-19 para el personal médico, a fin de realizar las acciones correspondientes en su ámbito de competencia para beneficio de la población.'),
(1372, 292, 'objetivo', 'Utilizar el PAI COVID-19 en su práctica profesional, a fin de homologar las actividades del equipo multidisciplinario de salud en los diferentes niveles de atención.'),
(1373, 292, 'contenido', '<ol>\r\n 	<li>Introducción</li>\r\n 	<li>Unidad PAI COVID-19</li>\r\n 	<li>Materiales complementarios</li>\r\n</ol>'),
(1374, 292, 'image', ''),
(1375, 293, '_wp_page_template', 'default'),
(1376, 293, 'dirigido_a', 'Personal de Enfermería de los tres niveles de atención del Instituto Mexicano del Seguro Social'),
(1377, 293, 'acerca', 'Desde el 30 de enero del 2020, la COVID-19 fue caracterizada como pandemia debido a sus niveles alarmantes de propagación. Hasta septiembre de 2022 se han reportado a nivel mundial más de 614 millones de casos y más de 6.5 millones de muertes a consecuencia de esta enfermedad. México se encuentra entre los países más afectados, con más de 7 millones de casos y más de 330 mil muertes.\r\n\r\nAnte esta problemática, el Instituto Mexicano del Seguro Social (IMSS) ha desarrollado un Protocolo de Atención Integral (PAI) en el que se establecen pautas de actuación del personal de salud de los tres niveles de atención, a fin de homologar las actividades referentes a la atención integral de pacientes con COVID-19.'),
(1378, 293, 'objetivo', 'Utilizar el PAI COVID-19 en su práctica profesional, a fin de homologar las actividades del equipo multidisciplinario de salud en los diferentes niveles de atención.'),
(1379, 293, 'contenido', '<ol>\r\n 	<li>Introducción</li>\r\n 	<li>Unidad PAI COVID-19</li>\r\n 	<li>Materiales complementarios</li>\r\n</ol>'),
