(1393, 297, '_wp_page_template', 'default'),
(1394, 297, 'dirigido_a', 'Personal médico adscrito al primer nivel de atención.'),
(1395, 297, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\nPor ello, se complace en poner al alcance del personal médico el curso Protocolo de Atención Integral (PAI) Asma bronquial en su modalidad en línea.\r\n\r\nEl propósito de este curso es establecer pautas de actuación del personal médico de los distintos niveles de atención para homologar las acciones referentes a la atención de pacientes con asma bronquial.'),
(1396, 297, 'objetivo', 'Utilizar el PAI Asma bronquial en su práctica profesional, a fin de homologar las actividades del personal médico en los diferentes niveles de atención.'),
(1397, 297, 'contenido', '<ul>\r\n 	<li>1. Introducción</li>\r\n 	<li>2. Unidad PAI Asma bronquial</li>\r\n 	<li>Materiales complementaros</li>\r\n</ul>'),
(1398, 297, 'image', ''),
(1399, 298, '_wp_page_template', 'default'),
(1400, 298, 'dirigido_a', 'Personal de Psicología, Nutrición y Trabajo Social de los tres níveles de atención.'),
(1401, 298, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\nPor ello, se complace en poner al alcance del equipo de salud el curso Protocolo de Atención Integral (PAI) Asma bronquial dirigido al equipo de salud en su modalidad en línea.\r\n\r\nEl propósito de este curso es establecer pautas de actuación del equipo de salud de los distintos niveles de atención para homologar las acciones referentes a la atención de pacientes con asma bronquial.'),
(1402, 298, 'objetivo', 'Identificar al Protocolo de Atención Integral Asma bronquial como un nuevo modelo de atención que permite homologar las acciones de prevención, diagnóstico y tratamiento de pacientes con esta enfermedad en los tres niveles de atención, a fin de utilizarlo en la práctica profesional.'),
(1403, 298, 'contenido', '<ul>\r\n 	<li>1. Introducción</li>\r\n 	<li>2. Unidad PAI Asma bronquial</li>\r\n</ul>'),
(1404, 298, 'image', ''),
(1405, 299, '_wp_page_template', 'default'),
(1406, 299, 'dirigido_a', 'Personal de Enfermería de los tres niveles de atención.'),
(1407, 299, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\nPor ello, se complace en poner al alcance del personal de Enfermería el curso Protocolo de Atención Integral (PAI) Asma bronquial en su modalidad en línea.\r\n\r\nEl propósito de este curso es establecer pautas de actuación del personal de Enfermería de los distintos niveles de atención para homologar las acciones referentes a la atención de pacientes con asma bronquial.'),
(1408, 299, 'objetivo', 'Utilizar el PAI Asma bronquial en su práctica profesional, a fin de homologar las actividades del personal de Enfermería en los diferentes niveles de atención.'),
(1409, 299, 'contenido', '<ul>\r\n 	<li>1. Introducción</li>\r\n 	<li>2. Unidad PAI Asma bronquial</li>\r\n</ul>'),
(1410, 299, 'image', ''),
(1411, 300, '_wp_page_template', 'default'),
(1412, 300, 'dirigido_a', 'Personal médico adscrito al primer nivel de atención.'),
(1413, 300, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\n\r\nPor ello, se complace en poner al alcance del personal de salud el curso Diagnóstico y tratamiento de la COVID-19 en población pediátrica, en su modalidad en línea.\r\n\r\nEl propósito de este curso es capacitar al personal médico del primer nivel de atención con conocimientos actualizados sobre el diagnóstico y tratamiento de la COVID-19 en población pediátrica, a fin de que los integre a su práctica profesional.'),
(1414, 300, 'objetivo', 'Establecer el diagnóstico y tratamiento de la COVID-19 en la población pediátrica, a fin de contribuir a la disminución de la morbimortalidad asociada con esta enfermedad.'),
(1415, 300, 'contenido', '<strong>Unidad 1</strong> Diagnóstico y tratamiento de la COVID-19 en población pediátrica\r\n\r\n<strong>Material complementari</strong>o\r\nBases para la atención de pacientes pediátricos con enfermedades infecciosas respiratorias agudas'),
(1416, 300, 'image', ''),
