(1420, 302, '_wp_page_template', 'default'),
(1421, 302, 'dirigido_a', 'Personal médico adscrito al primer nivel de atención.'),
(1422, 302, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\n\r\nPor ello, se complace en poner al alcance del personal de salud el curso Enfermedades infecciosas de las vías respiratorias bajas en población pediátrica, en su modalidad en línea.\r\n\r\nEl propósito de este curso es capacitar al personal médico del primer nivel de atención con conocimientos actualizados sobre el diagnóstico y tratamiento de las enfermedades infecciosas de las vías respiratorias bajas más comunes en la población pediátrica, a fin de integrarlos a su práctica profesional.'),
(1423, 302, 'objetivo', 'Establecer el diagnóstico y tratamiento oportunos de las enfermedades infecciosas de las vías respiratorias bajas más frecuentes en la población pediátrica, a fin de contribuir a la disminución de la morbimortalidad asociada con estos padecimientos.'),
(1424, 302, 'contenido', '<strong>Unidad 1.</strong> Laringotraqueobronquitis (crup)\r\n\r\n<strong>Unidad 2</strong>. Bronquiolitis\r\n\r\n<strong>Unidad 3.</strong> Neumonía adquirida en la comunidad en población pediátrica'),
(1425, 302, 'image', ''),
