(1429, 304, '_wp_page_template', 'default'),
(1430, 304, 'dirigido_a', 'Personal médico del primer nivel de atención.'),
(1431, 304, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\n\r\nPor ello, se complace en poner al alcance del personal médico el curso: Diagnóstico y tratamiento de los traumatismos de extremidades superiores más frecuentes en el primer nivel de atención, en su modalidad en línea. \r\n\r\nEl propósito de este curso es capacitar al personal médico sobre las acciones imprescindibles para la atención de personas con traumatismos en el primer nivel de atención, para que las apliquen en su práctica profesional y, con esto, coadyuvar en el mejoramiento del estado de salud de los pacientes afectados y mejorar su calidad de vida.'),
(1432, 304, 'objetivo', 'Establecer el diagnóstico y tratamiento de los traumatismos de extremidades superiores más frecuentes en el primer nivel de atención, a fin de otorgar una atención integral de las personas con estas lesiones.'),
(1433, 304, 'contenido', '<strong>Unidad 1.</strong> Traumatismos de hombro\r\n\r\n<strong>Unidad 2.</strong> Traumatismos de extremidades superiores'),
(1434, 304, 'image', ''),
