INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(1458, 310, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\n\r\nPor ello, se complace en poner al alcance del personal médico el curso: Diagnóstico y tratamiento de los esguinces más frecuentes en el primer nivel de atención, en su modalidad en línea. \r\n\r\nEl propósito de este curso es capacitar al personal médico sobre las acciones imprescindibles para la atención de personas con estos diagnósticos, en el primer nivel de atención, para que las apliquen en su práctica profesional y, con esto, coadyuvar en el mejoramiento del estado de salud de los pacientes afectados y mejorar su calidad de vida.'),
(1459, 310, 'objetivo', 'Establecer el diagnóstico y tratamiento de los esguinces más frecuentes en el primer nivel de atención, a fin de mejorar el pronóstico de los pacientes y disminuir el riesgo de complicaciones.'),
(1460, 310, 'contenido', '<strong>Unidad 1</strong>. Esguince de la columna cervical\r\n\r\n<strong>Unidad 2</strong>. Lesión por tracción de los ligamentos de la rodilla\r\n\r\n<strong>Unidad 3.</strong> Lesión por tracción de los ligamentos del tobillo'),
(1461, 310, 'image', ''),
