(1499, 319, '_wp_page_template', 'default'),
(1500, 319, 'dirigido_a', 'Personal médico y de nutrición'),
(1501, 319, 'acerca', 'La mala nutrición es un problema de salud pública en México; en este concepto se involucran entidades como la desnutrición, obesidad y sobrepeso que ocasionan diversas repercusiones como problemas de crecimiento y desarrollo en los niños, o el incremento del riesgo de desarrollar enfermedades crónico-degenerativas en la población general.\r\n\r\nPor lo cual, es imprescindible que el personal de salud intervenga de manera integral para prevenir o tratar las alteraciones del estado nutricional, dentro de un marco ético y normativo.\r\n\r\nPor tal motivo, la Dirección de Prestaciones Médicas, a través de la Coordinación de Educación en Salud, pone a su disposición el curso Temas selectos de nutrición, a fin de que adquiera herramientas que le permitan proporcionar intervenciones nutricionales con un enfoque integral.'),
(1502, 319, 'objetivo', 'Aplicar estrategias novedosas en la atención nutricional, bajo un marco ético y legal, a fin de distinguirlas como herramientas esenciales para propiciar la salud de la población'),
(1503, 319, 'contenido', '<strong>Unidad 1. <em>Coaching</em> ontológico aplicado en la nutrición</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades del <em>coaching</em> ontológico</li>\r\n 	<li>Tema 2. Coaching ontológico como herramienta en la consulta nutricional</li>\r\n 	<li>Tema 3. Etapas del cambio de conducta y el coaching ontologógico</li>\r\n</ul>\r\n<strong>Unidad 2. <em>Coaching</em> ontológico como herramienta en la consulta nutricional</strong>\r\n<ul>\r\n 	<li>Tema 1. Requerimientos nutricionales en el ejercicio físico</li>\r\n 	<li>Tema 2. Especificaciones dietéticas e hidratación en el ejercicio físico</li>\r\n 	<li>Tema 3. Suplementos y ayudas ergogénicas para el ejercicio físico y el deporte</li>\r\n</ul>\r\n<strong>Unidad 3. Genómica nutricional y nutrición personalizada</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades de la genómica nutricional</li>\r\n 	<li>Tema 2. Nutrición personalizada</li>\r\n</ul>\r\n<strong>Unidad 4. Mitos y realidades sobre la alimentación y nutrición</strong>\r\n<ul>\r\n 	<li>Tema 1. Mitos sobre la alimentación y nutrición en la población general</li>\r\n 	<li>Tema 2. Mitos relacionados con el embarazo, lactancia y enfermedades crónicas</li>\r\n</ul>\r\n<strong>Unidad 5. Interacción entre fármacos, nutrimentos y alimentos</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades de la interacción entre fármacos, nutrimentos y alimentos</li>\r\n 	<li>Tema 2. Interacción entre fármacos, nutrimentos y alimentos en casos especiales</li>\r\n</ul>\r\n<strong>Unidad 6. Marco normativo de la alimentación y la nutrición</strong>\r\n<ul>\r\n 	<li>Tema 1. Marco normativo internacional</li>\r\n 	<li>Tema 2. Marco normativo nacional e institucional</li>\r\n</ul>\r\n<strong>Unidad 7. Soporte nutricional</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades del soporte nutricional</li>\r\n 	<li>Tema 2. Tipos de soporte nutricional</li>\r\n</ul>\r\n<strong>Unidad 8. Estrategias para la educación alimentaria y nutricional</strong>\r\n<ul>\r\n 	<li>Tema 1. La educación alimentaria y nutricional a nivel internacional</li>\r\n 	<li>Tema 2. La educación alimentaria y nutricional en México</li>\r\n</ul>\r\n<strong>Unidad 9. Ética en la atención nutricional</strong>\r\n<ul>\r\n 	<li>Tema 1. Generalidades de la ética profesional</li>\r\n 	<li>Tema 2. Marco ético de la atención nutricional</li>\r\n</ul>'),
