(1525, 323, '_thumbnail_id', '324'),
(1526, 325, '_wp_page_template', 'default'),
(1527, 325, 'dirigido_a', 'Personal de Enfermería de los tres niveles de atención'),
(1528, 325, 'acerca', 'El proceso de atención de Enfermería (PAE) es una herramienta que permite proporcionar una atención integral a través de una serie de intervenciones sustentadas en el método científico. Además, los cuidados de Enfermería generan amplios beneficios al paciente, como son: una recuperación rápida, mayor confort durante su estancia hospitalaria, la disminución de complicaciones, entre muchos otros.\r\n\r\nEn este sentido, es imprescindible que el personal de Enfermería identifique las etapas que conforman el PAE y las consideraciones pertinentes a realizar durante la atención de pacientes que padezcan trastornos del aparato digestivo, con el propósito de alcanzar los beneficios mencionados.\r\n\r\nPor tal motivo, la Dirección de Prestaciones Médicas, a través de la Coordinación de Educación en Salud, pone a su disposición el curso Intervenciones de Enfermería en pacientes con trastornos del aparato digestivo, a fin de que adquiera herramientas que favorezcan la organización de planes de cuidados para la atención de la población con este tipo de afecciones.'),
(1529, 325, 'objetivo', 'Aplicar intervenciones de Enfermería en la población adulta afectada por los principales trastornos del aparato digestivo, a fin de coadyuvar en su control o remisión.'),
(1530, 325, 'contenido', '<strong>Unidad 1. Fundamentos para la atención de trastornos del aparato digestivo</strong>\r\n<ul>\r\n 	<li>Tema 1. Anatomía y fisiología del aparato digestivo</li>\r\n 	<li>Tema 2. Proceso de atención de Enfermería en pacientes con trastornos del aparato digestivo</li>\r\n</ul>\r\n<strong>Unidad 2. Trastornos bucales y gastroesofágicos</strong>\r\n<ul>\r\n 	<li>Tema 1. Trastornos de la cavidad bucal</li>\r\n 	<li>Tema 2. Trastornos gastroesofágicos</li>\r\n</ul>\r\n<strong>Unidad 3. Trastornos intestinales</strong>\r\n<ul>\r\n 	<li>Tema 1. Trastornos del intestino delgado</li>\r\n 	<li>Tema 2. Trastornos del intestino grueso</li>\r\n</ul>\r\n<strong>Unidad 4. Trastornos hepáticos y pancreáticos</strong>\r\n<ul>\r\n 	<li>Tema 1. Trastornos hepáticos</li>\r\n 	<li>Tema 2. Trastornos pancreáticos</li>\r\n</ul>'),
(1531, 325, 'image', ''),
