(1616, 345, '_wp_page_template', 'default'),
(1617, 345, 'dirigido_a', 'Personal de Enfermería de los tres niveles de atención del Instituto Mexicano del Seguro Social.'),
(1618, 345, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\nPor ello, se complace en poner al alcance del personal de Enfermería de los tres niveles de atención el curso Protocolo de Atención Integral (PAI) Cáncer de próstata, en su modalidad en línea.\r\nEl propósito de este curso es capacitar a los profesionales de esta disciplina sobre el PAI Cáncer de próstata, desarrollado por el Instituto para estandarizar acciones de prevención, diagnóstico y tratamiento de pacientes con esta enfermedad.'),
(1619, 345, 'objetivo', 'Utilizar el Protocolo de Atención Integral Cáncer de próstata en su práctica profesional, a fin de homologar las actividades del equipo multidisciplinario de salud en los diferentes niveles de atención'),
(1620, 345, 'contenido', 'Tema 1 Promoción de la salud\r\n\r\nTema 2 Prevención\r\n\r\nTema 3 Tratamiento\r\n\r\nEvaluación Unidad PAI Cáncer de próstata'),
