(1728, 369, '_wp_page_template', 'default'),
(1729, 369, 'dirigido_a', 'Personal de Enfermería de los tres niveles de atención del IMSS.'),
(1730, 369, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\n\r\nPor ello, se complace en poner al alcance del personal de Enfermería de los tres niveles de atención el curso PAI Insuficiencia cardiaca y trasplante de corazón para el personal de Enfermería, en su modalidad en línea.\r\n\r\nEl propósito de este curso es capacitar al personal de Enfermería sobre el Protocolo de acción integral (PAI) Insuficiencia cardiaca y trasplante de corazón, desarrollado por el Instituto para estandarizar acciones de prevención, diagnóstico y tratamiento de pacientes con estas condiciones.'),
(1731, 369, 'objetivo', 'Utilizar el PAI Insuficiencia cardiaca y trasplante de corazón en su práctica profesional, a fin de homologar las actividades del equipo multidisciplinario de salud en los diferentes niveles de atención.'),
(1732, 369, 'contenido', '<ol>\r\n 	<li>Introducción</li>\r\n 	<li>Unidad PAI Insuficiencia cardiaca y trasplante de corazón</li>\r\n 	<li> Materiales complementarios</li>\r\n</ol>'),
(1733, 369, 'image', ''),
