(1825, 390, 'dirigido_a', 'Personal directivo y trabajador de los tres niveles de atención'),
(1826, 390, 'acerca', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto.\r\n\r\nPor ello, se complace en poner al alcance del personal de salud el curso Desarrollo sostenible en establecimientos de salud en su modalidad en línea.'),
(1827, 390, 'objetivo', 'Identificar los fundamentos del desarrollo sostenible en los establecimientos de salud, a fin de emplearlos en la implementación de estrategias orientadas al cuidado del medio ambiente'),
(1828, 390, 'contenido', 'Unidad 1\r\nIntroducción al desarrollo sostenible\r\n\r\nUnidad 2\r\nGobernanza y desarrollo sostenible\r\n\r\nUnidad 3\r\nConstrucción de los establecimientos de salud con enfoque de sostenibilidad\r\n\r\nUnidad 4\r\nCalidad de vida y desarrollo sostenible\r\n\r\nUnidad 5\r\nGestión del agua en los establecimientos de salud\r\n\r\nUnidad 6\r\nGestión integral de residuos\r\n\r\nUnidad 7\r\nGestión energética en los establecimientos de salud\r\n\r\nUnidad 8\r\nCompras sostenibles en los establecimientos de salud'),
(1829, 390, 'image', ''),
(1830, 391, '_wp_attached_file', '2026/04/Ban_DSES_V1A_1440x490.png');
