(1886, 402, '_thumbnail_id', '403'),
(1887, 404, '_wp_page_template', 'default'),
(1888, 404, 'dirigido_a', 'Personal médico adscrito al primer nivel de atención.'),
(1889, 404, 'acerca', 'Las enfermedades infecciosas de las vías respiratorias altas en la edad pediátrica representan uno de los principales motivos de consulta en la atención primaria y constituyen un problema de salud pública por su elevada frecuencia y contagiosidad. Estas patologías generalmente son de etiología viral, evolución no complicada y de resolución espontánea, sin embargo, constituyen una de las principales razones por las cuales se prescriben antibióticos de manera indiscriminada; además, un diagnóstico o un tratamiento incorrectos pueden derivar en complicaciones graves, por lo que es fundamental la actualización del personal médico de primer nivel en estos aspectos.\r\n \r\nPor ello, la Dirección de Prestaciones Médicas del IMSS considera fundamental la capacitación del personal médico a través de este curso, a fin de reforzar sus conocimientos para establecer el diagnóstico y tratamiento de las enfermedades infecciosas de las vías respiratorias altas más frecuentes en la población pediátrica, lo cual permitirá optimizar el proceso de atención y prevenir complicaciones.'),
(1890, 404, 'objetivo', 'Establecer el diagnóstico y tratamiento oportunos de las enfermedades infecciosas de las vías respiratorias altas más frecuentes en la población pediátrica, a fin de contribuir a la disminución de la morbimortalidad asociada con estos padecimientos.'),
(1891, 404, 'contenido', '<strong>Unidad 1.</strong> Rinofaringitis en población pediátrica\r\n\r\n<strong>Unidad 2</strong>. Otitis media aguda en población pediátrica\r\n\r\n<strong>Unidad 3.</strong> Faringoamigdalitis aguda en población pedátrica\r\n\r\n<strong>Unidad 4.</strong> Rinosinusitis aguda en población pediátrica'),
(1892, 404, 'image', ''),
