INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(2495, 65, '_thumbnail_id', '411'),
(2496, 412, '_wp_page_template', 'default'),
(2497, 412, 'dirigido_a', 'Personal médico de primer nivel de atención del Instituto Mexicano del Seguro Social.'),
(2498, 412, 'objetivo', 'Al finalizar el curso, usted será capaz de: Utilizar el conocimiento para realizar el uso correcto de equipo de protección personal, higiene de manos y retiro del equipo de protección personal.'),
(2499, 412, 'codigo_api', ''),
(2500, 413, '_wp_page_template', 'default'),
(2501, 413, 'dirigido_a', 'Personal médico de nivel hospitalario del Instituto Mexicano del Seguro Social.'),
(2502, 413, 'objetivo', 'Al finalizar el curso, usted será capaz de: Utilizar el conocimiento para realizar el uso correcto de equipo de protección personal, higiene de manos y retiro del equipo de protección personal.'),
(2503, 413, 'codigo_api', ''),
(2504, 414, '_wp_page_template', 'default'),
(2505, 414, 'dirigido_a', 'Personal operativo médico y de enfermería de unidad de medicina familiar y hospitales del IMSS'),
(2506, 414, 'objetivo', 'Que el personal de salud adquiera el conocimiento y habilidades para dar malas noticias en seis pasos sencillos para mejorar la calidad y calidez en la atención clínica.'),
(2507, 414, 'codigo_api', ''),
(2508, 415, '_wp_page_template', 'default'),
(2509, 415, 'dirigido_a', 'Personal médico de primer, segundo y tercer nivel de atención del Instituto Mexicano del Seguro Social.'),
(2510, 415, 'objetivo', 'En esta modalidad de microlecciones, usted adquirirá herramientas para llevar a cabo un tamizaje y elementos para la toma de decisiones con respecto a lo resultante en relación a depresión, ansiedad, riesgo suicida, estrés postraumático y trastornos mentales y del comportamiento debidos al consumo de sustancias psicotrópicas.'),
(2511, 415, 'codigo_api', ''),
(2512, 416, '_wp_page_template', 'default'),
(2513, 416, 'dirigido_a', 'Personal médico de primer, segundo y tercer nivel de atención del IMSS'),
(2514, 416, 'objetivo', 'Que el personal de salud adquiera el conocimiento para realizar una correcta prescripción y en su caso transcripción de oxígeno suplementario para paciente ambulatorio post-COVID 19'),
(2515, 416, 'codigo_api', ''),
(2516, 417, '_wp_page_template', 'default'),
(2517, 417, 'dirigido_a', 'Personal de Enfermería de Módulos PrevenIMSS y Módulos de Enfermería Especialista en Medicina de Familia'),
(2518, 417, 'objetivo', 'Al finalizar la microlección, el alumno será capaz de dentificar las características del cuestionario de salud mental y la metodología para su aplicación, a fin de utilizar este instrumento para el tamizaje de los trastornos de ansiedad, depresión y pánico en el primer nivel de atención.'),
(2519, 417, 'codigo_api', 'CES-TSMD20'),
(2520, 418, '_wp_page_template', 'default'),
(2521, 418, 'dirigido_a', 'Personal de Enfermería contratado por tiempo determinado en áreas médicas (PTDAM)'),
(2522, 418, 'objetivo', 'Identificar las características del cuestionario de salud mental y la metodología para su aplicación, a fin de utilizar este instrumento para el tamizaje de los trastornos de ansiedad, depresión y pánico en población derechohabiente durante el chequeo PrevenIMSS extramuros en empresas y escuelas públicas de nivel medio superior y superior.'),
(2523, 418, 'codigo_api', 'CES-TSMPDEE'),
(2524, 419, '_wp_page_template', 'default'),
(2525, 419, 'dirigido_a', 'Personal de Enfermería de módulos SPPSTIMSS'),
(2526, 419, 'objetivo', 'Distinguir las características del cuestionario de salud mental y la metodología para su aplicación, a fin de utilizar este instrumento para la identificación de trastornos de ansiedad, depresión y pánico en los trabajadores del IMSS durante el chequeo anual PrevenIMSS'),
(2527, 419, 'codigo_api', 'CES-TSMTR'),
(2528, 420, '_wp_page_template', 'default'),
(2529, 420, 'dirigido_a', 'Personal directivo y operativo del Instituto Mexicano del Seguro Social.'),
(2530, 420, 'objetivo', 'Que el personal de salud adquiera el conocimiento para realizar una detección y manejo en personas que presenten algún factor de riesgo para adquirir la infección por el Virus de la Inmunodeficiencia Humana.'),
(2531, 420, 'codigo_api', ''),
(2532, 421, '_wp_page_template', 'default'),
(2533, 421, 'dirigido_a', 'Personal médico directivo y operativo involucrado en el programa.'),
(2534, 421, 'objetivo', 'Que el personal de salud adquiera el conocimiento para realizar o dirigir una Profilaxis Post Exposición (PEP) para VIH.'),
(2535, 421, 'codigo_api', ''),
(2536, 422, '_wp_page_template', 'default'),
(2537, 422, 'dirigido_a', 'Personal de salud de los tres niveles de atención'),
(2538, 422, 'objetivo', 'Que el personal de salud identifique los elementos a considerar en la elaboración de reactivos de opción múltiple, a fin de realizar pruebas eficaces para evaluar el logro de los objetivos de aprendizaje.'),
(2539, 422, 'codigo_api', ''),
(2540, 423, '_wp_page_template', 'default'),
(2541, 423, 'dirigido_a', 'Personal médico adscrito a la consulta de Medicina Familiar: - Médicos familiares - Médicos generales Jefes de departamento adscritos a Unidades de Medicina Familiar.'),
(2542, 423, 'objetivo', 'Al finalizar la microlección, el alumno será capaz de:Emplear la terapia dual o triple en pacientes con Hipertensión arterial sistémica (HAS), con base en el riesgo cardiovascular, a fin de lograr las metas de control óptimo y evitar la inercia terapéutica.'),
(2543, 423, 'codigo_api', 'CES-TDTPPHAS'),
(2544, 424, '_wp_page_template', 'default'),
(2545, 424, 'dirigido_a', 'Personal médico directivo y operativo de primer nivel de atención, pediatras, traumatólogos ortopedistas y otros médicos especialistas no familiares, Personal de enfermería en general de los tres niveles de atención.'),
(2546, 424, 'objetivo', 'Que el personal de salud adquiera el conocimiento para realizar una detección temprana de cáncer en infancia y adolescencia'),
(2547, 424, 'codigo_api', 'CES-DTCIA'),
(2548, 425, '_wp_page_template', 'default'),
(2549, 425, 'dirigido_a', 'Personal médico y de Enfermería en los servicios de Oncología y Hematología pediátrica.'),
(2550, 425, 'objetivo', 'Que el personal de salud adquiera el conocimiento para identificar los instrumentos para la Escala de Valoración de Alerta Temprana (EVAT) a fin de utilizarlos de manera correcta durante la atención integral del paciente pediátrico oncológico hospitalizado.'),
(2551, 425, 'codigo_api', 'CES-EVAT'),
(2552, 426, '_wp_page_template', 'default'),
(2553, 426, 'dirigido_a', 'Personal médico y de enfermería de segundo y tercer nivel de atención.'),
(2554, 426, 'objetivo', 'Al finalizar la microlección, el alumno será capaz de Identificar las características del programa Hora dorada y las acciones correspondientes al personal médico y de Enfermería, a fin de utilizarlas para la atención integral del paciente pediátrico oncológico con fiebre y neutropenia.'),
(2555, 426, 'codigo_api', 'CES-HDMSV'),
(2556, 427, '_wp_page_template', 'default'),
(2557, 427, 'dirigido_a', 'Personal de Enfermería operativas y gerenciales que tengan a su cuidado mujeres embarazadas de bajo riesgo'),
(2558, 427, 'objetivo', 'Que el personal de salud pueda utilizar la Psicoprofilaxis Perinatal como parte de la Ciencia del Cuidado de Enfermería en las unidades con atención de mujeres en la gestación de bajo riesgo a fin de emplear técnicas de relajación, manejo del dolor con ayuda de aromaterapia y musicoterapia que logre que el parto sea una experiencia única, bajo el Cuidado profesional de Enfermería'),
(2559, 427, 'codigo_api', ''),
(2560, 428, '_wp_page_template', 'default'),
(2561, 428, 'dirigido_a', 'Personal Enfermería de primer, segundo y tercer nivel de atención del IMSS y personal de confianza. El micro contenido está en formato de fases secuenciales y progresivas.'),
(2562, 428, 'objetivo', 'Que el personal de salud adquiera el conocimiento para realizar e implementar Proyectos de investigación de enfermería.'),
(2563, 428, 'codigo_api', ''),
(2564, 429, '_wp_page_template', 'default'),
(2565, 429, 'dirigido_a', 'Personal de Salud de primer, segundo y tercer nivel de atención del IMSS y personal de confianza.'),
(2566, 429, 'objetivo', 'Que el personal de salud adquiera el conocimiento para realizar e implementar la estrategia institucional proactiva para impulsar una cultura de atención a la salud que pueda afrontar y corregir el rumbo de este importante tema de salud pública.'),
(2567, 429, 'codigo_api', ''),
(2568, 430, '_wp_page_template', 'default'),
(2569, 430, 'dirigido_a', 'Personal directivo y operativo de las unidades médicas de los tres niveles de atención'),
(2570, 430, 'objetivo', 'Al finalizar la microlección, el alumno será capaz de: \r\nDistinguir las consideraciones para la medición del consumo de antibióticos en las unidades médicas del Instituto, a fin de utilizar dicha información para el diseño e implementación de intervenciones de mejora en su prescripción.'),
(2571, 430, 'codigo_api', 'CES-MCA'),
(2572, 431, '_wp_page_template', 'default'),
(2573, 431, 'dirigido_a', 'Personal de salud de los tres niveles de atención.'),
(2574, 431, 'objetivo', 'Infecciones asociadas a la atención de la salud, mediante la cual comprenderá la importancia de aplicar los paquetes de acciones preventivas en su ámbito de competencia, a fin de reducir la incidencia y complicaciones de dichas afecciones. \r\n\r\nIdentificar los aspectos conceptuales y epidemiológicos de las infecciones asociadas a la atención de la salud (IAAS), así como los protocolos de acción para su prevención y control, para aplicarlos en su práctica profesional y prevenir complicaciones en los pacientes'),
(2575, 431, 'codigo_api', 'CES-GIAAS'),
(2576, 432, '_wp_page_template', 'default'),
(2577, 432, 'dirigido_a', 'Personal médico y de Psicología adscrito al primer nivel de atención.'),
(2578, 432, 'objetivo', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y en América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto. \r\n\r\nPor ello, se complace en poner a su alcance las micro lecciones las intervenciones psicológicas de baja intensidad, mediante la que podrá obtener una visión general de los recursos en salud mental que pueden aplicarse durante la atención de personas con dificultades mentales. El objetivo es mejorar la calidad de vida y disminuir el estigma, así como la discriminación que enfrentan estos pacientes.'),
(2579, 432, 'codigo_api', 'CES-IIPBI'),
(2580, 433, '_wp_page_template', 'default'),
(2581, 433, 'dirigido_a', 'Personal médico y de enfermería de primer nivel de atención'),
(2582, 433, 'objetivo', 'La Coordinación de Educación en Salud tiene como visión que el Instituto Mexicano del Seguro Social (IMSS) forme y disponga de los mejores profesionales de la salud en el país y América Latina para beneficio de toda la sociedad. Su propósito es mejorar la calidad, oportunidad y cobertura de los procesos de educación para el personal que labora en el Instituto. \r\n\r\nPor ello, se complace en poner a su alcance las micro lecciones Profilaxis oral pre-exposición al VIH, mediante la cual identificará los principales aspectos de dicha estrategia, a fin de que reconozca la importancia de aplicarla en la población, para reducir el riesgo de contraer la infección.'),
(2583, 433, 'codigo_api', 'CES-GPOPEVIH'),
(2584, 434, '_wp_page_template', 'default'),
(2585, 434, 'dirigido_a', 'Personal médico (de las especialidades de Pediatría, Hematología pediátrica, Oncología pediátrica, Cirugía pediátrica, Cirugía oncológica pediátrica y Ortopedia), Enfermería y Trabajo Social.'),
(2586, 434, 'objetivo', 'Al finalizar la microlección, el alumno será capaz de:\r\n\r\nIdentificar conceptos básicos en rehabilitación oncológica pediátrica, así como la estructura y función de los equipos inter, multi y transdisciplinario, para reconocer su importancia en el manejo de la niña, niño y adolescente con cáncer.'),
(2587, 434, 'codigo_api', 'CES-SIBRNAC'),
