(5306, 488, '_modulos_plantilla_interna', 'field_plantilla_interna_modulos'),
(5307, 484, 'modulos_plantilla_interna_1_titulo', 'Capacitación para personal extrainstitucional'),
(5308, 484, '_modulos_plantilla_interna_1_titulo', 'field_bloque_info_titulo'),
(5309, 484, 'modulos_plantilla_interna_1_contenido', 'En el IMSS, la Coordinación de Educación en Salud (CES) es la única instancia normativa facultada para autorizar el ingreso de personal externo, y realicen actividades académico-asistenciales en las unidades médicas en los tres niveles de atención y en las Unidades Médicas de Alta Especialidad.\r\n\r\nPara ello el personal designado por la CES recibe las solicitudes del personal extrainstitucional que desea capacitarse en el IMSS a través de cursos presenciales de Alta Especialización, Adiestramientos en el Trabajo y Temáticos con Prácticas, que se implementan en las unidades médicas.\r\n\r\nConmutador: 23333i3. Ext 290, 909'),
(5310, 484, '_modulos_plantilla_interna_1_contenido', 'field_bloque_info_contenido'),
